#include <iostream>
using namespace std;

int main() {
    int a, b;
    cout << \Введите два числа: ";
    cin >> a >> b;
    int product = a * b;
    while(b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    cout << "НОК: " << product / a << endl;
    return 0;
}"

#include <iostream>

int main() {
    int a, b;
    std::cout << \Введите два числа: ";
    std::cin >> a >> b;
    int product = a * b;
    while(b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    std::cout << "НОК: " << product / a << std::endl;
    return 0;
}"

#include <iostream>
using namespace std;

int main() {
    int num;
    cout << \Введите число: ";
    cin >> num;
    cout << "Делители: ";
    for(int i = 1; i <= num; i++) {
        if(num % i == 0) cout << i << " ";
    }
    cout << endl;
    return 0;
}"

#include <iostream>

int main() {
    int num;
    std::cout << \Введите число: ";
    std::cin >> num;
    std::cout << "Делители: ";
    for(int i = 1; i <= num; i++) {
        if(num % i == 0) std::cout << i << " ";
    }
    std::cout << std::endl;
    return 0;
}"

#include <iostream>
using namespace std;

int main() {
    int num;
    cout << \Введите число: ";
    cin >> num;
    bool isPower = (num > 0) && ((num & (num - 1)) == 0);
