#include <iostream>
using namespace std;

int main() {
    int n;
    cout << \Введите N: ";
    cin >> n;

    for (int i = 2; i <= n; i++) {
        bool is_prime = true;
        for (int j = 2; j * j <= i; j++) {
            if (i % j == 0) {
                is_prime = false;
                break;
            }
        }
        if (is_prime) {
            cout << i << " ";
        }
    }
    cout << endl;
    return 0;
}"

#include <iostream>

