#include <iostream>
using namespace std;

int main() {
    int n;
    cout << \Введите число: ";
    cin >> n;

    if (n < 2) {
        cout << "Число не является простым" << endl;
        return 0;
    }

    bool is_prime = true;
    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            is_prime = false;
            break;
        }
    }

    if (is_prime) {
        cout << n << " - простое число" << endl;
    } else {
        cout << n << " - составное число" << endl;
    }
    return 0;
}"

#include <iostream>

int main() {
    int n;
    std::cout << \Введите число: ";
    std::cin >> n;

    if (n < 2) {
        std::cout << "Число не является простым" << std::endl;
        return 0;
    }

    bool is_prime = true;
    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            is_prime = false;
            break;
        }
    }

    if (is_prime) {
        std::cout << n << " - простое число" << std::endl;
    } else {
        std::cout << n << " - составное число" << std::endl;
    }
    return 0;
}"

#include <iostream>
using namespace std;

int main() {
    double a, b;
    char op;

    cout << \Введите выражение (например 2 + 3): ";
    cin >> a >> op >> b;

    switch (op) {
        case '+':
            cout << "Результат: " << a + b << endl;
            break;
        case '-':
            cout << "Результат: " << a - b << endl;
            break;
        case '*':
            cout << "Результат: " << a * b << endl;
            break;
        case '/':
            if (b != 0) {
                cout << "Результат: " << a / b << endl;
            } else {
                cout << "Ошибка: деление на ноль!" << endl;
            }
            break;
        default:
            cout << "Неизвестная операция!" << endl;
    }
    return 0;
}"

