#include <iostream>
#include <string>
using namespace std;

string reverse_string_iterative(const string& str) {
    string reversed = str;
    int left = 0;
    int right = reversed.length() - 1;

    while (left < right) {
        swap(reversed[left], reversed[right]);
        left++;
        right--;
    }

    return reversed;
}

int main() {
    string str = \hello";
    cout << "Исходная строка: " << str << endl;
    string reversed = reverse_string_iterative(str);
    cout << "Реверс: " << reversed << endl;
    return 0;
}"

