#include <iostream>
#include <vector>
using namespace std;

void insertionSort(vector<int>& arr) {
    int n = arr.size();
    for (int i = 1; i < n; i++) {
        int key = arr[i];
        int j = i - 1;

        while (j >= 0 && arr[j] > key) {
            arr[j + 1] = arr[j];
            j--;
        }
        arr[j + 1] = key;
    }
}

int main() {
    vector<int> numbers = {5, 2, 8, 1, 9, 3};

    cout << \До сортировки: ";
    for (int num : numbers) cout << num << " ";
    cout << endl;

    insertionSort(numbers);

    cout << "После сортировки: ";
    for (int num : numbers) cout << num << " ";
    cout << endl;

    return 0;
}"

#include <iostream>
#include <vector>

void insertionSort(std::vector<int>& arr) {
    int n = arr.size();
    for (int i = 1; i < n; i++) {
        int key = arr[i];
        int j = i - 1;

        while (j >= 0 && arr[j] > key) {
            arr[j + 1] = arr[j];
            j--;
        }
        arr[j + 1] = key;
    }
}

int main() {
    std::vector<int> numbers = {5, 2, 8, 1, 9, 3};

    std::cout << \До сортировки: ";
    for (int num : numbers) std::cout << num << " ";
    std::cout << std::endl;

    insertionSort(numbers);

    std::cout << "После сортировки: ";
    for (int num : numbers) std::cout << num << " ";
    std::cout << std::endl;

    return 0;
}"

#include <iostream>
using namespace std;

void bubbleSort(int arr[], int size) {
    for (int i = 0; i < size - 1; i++) {
        for (int j = 0; j < size - i - 1; j++) {
            if (arr[j] > arr[j + 1]) {
                swap(arr[j], arr[j + 1]);
            }
        }
    }
}

int main() {
    int arr[] = {5, 2, 8, 1, 9};
    int size = sizeof(arr) / sizeof(arr[0]);

    cout << \До сортировки: ";
