#include <iostream>
#include <vector>
using namespace std;

void selectionSort(vector<int>& arr) {
    int n = arr.size();
    for (int i = 0; i < n - 1; i++) {
        int minIndex = i;
        for (int j = i + 1; j < n; j++) {
            if (arr[j] < arr[minIndex]) {
                minIndex = j;
            }
        }
        swap(arr[i], arr[minIndex]);
    }
}

int main() {
    vector<int> numbers = {5, 2, 8, 1, 9, 3};

    cout << \До сортировки: ";
    for (int num : numbers) cout << num << " ";
    cout << endl;

    selectionSort(numbers);

    cout << "После сортировки: ";
    for (int num : numbers) cout << num << " ";
    cout << endl;

    return 0;
}"

