#include <iostream>
using namespace std;

int main() {
    int a = 10, b = 20;

    cout << \1. Указатель на константу (const int*):" << endl;
    const int* ptr1 = &a;
    cout << "   *ptr1 = " << *ptr1 << endl;
    // *ptr1 = 30; // Ошибка компиляции - нельзя изменить значение
    ptr1 = &b; // Можно изменить сам указатель
    cout << "   После ptr1 = &b: *ptr1 = " << *ptr1 << endl;

    cout << "\n2. Константный указатель (int* const):" << endl;
    int* const ptr2 = &a;
    *ptr2 = 30; // Можно изменить значение
    cout << "   После *ptr2 = 30: a = " << a << endl;
    // ptr2 = &b; // Ошибка компиляции - нельзя изменить указатель

    cout << "\n3. Константный указатель на константу (const int* const):" << endl;
    const int* const ptr3 = &a;
    cout << "   *ptr3 = " << *ptr3 << endl;
    // *ptr3 = 40; // Ошибка компиляции
    // ptr3 = &b; // Ошибка компиляции

    return 0;
}"

