    // *ptr1 = 30; // Ошибка компиляции - нельзя изменить значение
    ptr1 = &b; // Можно изменить сам указатель
    std::cout << "   После ptr1 = &b: *ptr1 = " << *ptr1 << std::endl;

    std::cout << "\n2. Константный указатель (int* const):" << std::endl;
    int* const ptr2 = &a;
    *ptr2 = 30; // Можно изменить значение
    std::cout << "   После *ptr2 = 30: a = " << a << std::endl;
    // ptr2 = &b; // Ошибка компиляции - нельзя изменить указатель

    std::cout << "\n3. Константный указатель на константу (const int* const):" << std::endl;
    const int* const ptr3 = &a;
    std::cout << "   *ptr3 = " << *ptr3 << std::endl;
    // *ptr3 = 40; // Ошибка компиляции
    // ptr3 = &b; // Ошибка компиляции

    return 0;
}"

