#include <iostream>
using namespace std;

void swap(int& a, int& b) {
    int temp = a;
    a = b;
    b = temp;
}

void increment(int& value) {
    value++;
}

int main() {
    int x = 5, y = 10;

    cout << \До обмена: x = " << x << "

keywords:
 y = " << y << endl;

    increment(x);
    cout << "После инкремента: x = " << x << endl;

    return 0;
}"

