#include <iostream>
using namespace std;

struct Settings {
    unsigned int soundEnabled : 1;    // 1 бит
    unsigned int musicEnabled : 1;    // 1 бит
    unsigned int difficulty : 2;      // 2 бита (0-3)
    unsigned int volume : 4;          // 4 бита (0-15)
    unsigned int level : 6;           // 6 бит (0-63)
};

int main() {
    Settings settings;

    settings.soundEnabled = 1;
    settings.musicEnabled = 0;
    settings.difficulty = 2;  // Средняя сложность
    settings.volume = 12;     // Громкость 12/15
    settings.level = 25;      // Уровень 25

    cout << \Настройки игры:" << endl;
    cout << "Звук: " << (settings.soundEnabled ? "вкл" : "выкл") << endl;
    cout << "Музыка: " << (settings.musicEnabled ? "вкл" : "выкл") << endl;
    cout << "Сложность: " << settings.difficulty << endl;
    cout << "Громкость: " << settings.volume << "/15" << endl;
    cout << "Уровень: " << settings.level << endl;

    cout << "\nРазмер структуры: " << sizeof(Settings) << " байт" << endl;

    return 0;
}"

