#include <iostream>
using namespace std;

class Circle {
 const double radius; // Константное поле
 mutable int accessCount; // Может изменяться даже в константных методах
public:
 Circle(double r) : radius(r), accessCount(0) {}
 double getArea() const {
 accessCount++;
 return 3.14159 * radius * radius;
 }
 double getCircumference() const {
 accessCount++;
 return 2 * 3.14159 * radius;
 }
 int getAccessCount() const { return accessCount; }
};

int main() {
 const Circle circle(5.0); // Константный объект
 cout << \Area: " << circle.getArea() << endl;
 cout << "Circumference: " << circle.getCircumference() << endl;
 cout << "Methods called: " << circle.getAccessCount() << " times" << endl;
 return 0;
}"

#include <iostream>

class Circle {
 const double radius; // Константное поле
 mutable int accessCount; // Может изменяться даже в константных методах
public:
 Circle(double r) : radius(r), accessCount(0) {}
 double getArea() const {
 accessCount++;
 return 3.14159 * radius * radius;
 }
 double getCircumference() const {
 accessCount++;
 return 2 * 3.14159 * radius;
 }
 int getAccessCount() const { return accessCount; }
};

int main() {
 const Circle circle(5.0); // Константный объект
 std::cout << \Area: " << circle.getArea() << std::endl;
 std::cout << "Circumference: " << circle.getCircumference() << std::endl;
 std::cout << "Methods called: " << circle.getAccessCount() << " times" << std::endl;
 return 0;
}"

#include <iostream>
#include <string>
using namespace std;

class Cache {
 mutable string cachedValue;
 mutable bool isValid;
 string computeValue() const {
 return \Computed at: " + to_string(time(nullptr));
 }
public:
 Cache() : isValid(false) {}
 string getValue() const {
 if(!isValid) {
 cachedValue = computeValue();
 isValid = true;
 cout << "Value computed and cached" << endl;
 }
 return cachedValue;
 }
 void invalidate() const { isValid = false; } // Может быть const благодаря mutable
};

int main() {
 const Cache cache;
 cout << cache.getValue() << endl;
 cout << cache.getValue() << endl; // Используется кэшированное значение
 cache.invalidate();
 cout << cache.getValue() << endl; // Вычисляется заново
 return 0;
}"

