}"

#include <iostream>
using namespace std;

class TrafficLight {
public:
 enum class State { RED, YELLOW, GREEN }; // Scoped enum
private:
 State currentState;
public:
 TrafficLight() : currentState(State::RED) {}
 void next() {
 switch(currentState) {
 case State::RED: currentState = State::GREEN; break;
 case State::GREEN: currentState = State::YELLOW; break;
 case State::YELLOW: currentState = State::RED; break;
 }
 }
 string getState() const {
 switch(currentState) {
 case State::RED: return \RED";
 case State::GREEN: return "GREEN";
 case State::YELLOW: return "YELLOW";
 default: return "UNKNOWN";
 }
 }
};

int main() {
 TrafficLight light;
 for(int i = 0; i < 5; i++) {
 cout << "Light is: " << light.getState() << endl;
 light.next();
 }
 return 0;
}"

