#include <iostream>
using namespace std;

class Packet {
public:
 // Битовые поля
 unsigned int version : 4; // 4 бита
 unsigned int headerLength : 4; // 4 бита
 unsigned int type : 2; // 2 бита
 unsigned int priority : 3; // 3 бита
 unsigned int reserved : 1; // 1 бит
 Packet() : version(1), headerLength(5), type(0), priority(0), reserved(0) {}
 void display() const {
 cout << \Version: " << version << endl;
 cout << "Header Length: " << headerLength << endl;
 cout << "Type: " << type << endl;
 cout << "Priority: " << priority << endl;
 cout << "Reserved: " << reserved << endl;
 cout << "Total bits: " << (4+4+2+3+1) << endl;
 }
};

int main() {
 Packet pkt;
 pkt.display();
 pkt.version = 2;
 pkt.priority = 5;
 cout << "\nAfter modification:" << endl;
 pkt.display();
 return 0;
}"

