#include <iostream>
#include <cmath>
using namespace std;

class Circle {
 double radius;
 mutable double cachedArea; // Может изменяться в константных методах
 mutable bool areaValid; // Флаг валидности кэша
public:
 Circle(double r) : radius(r), cachedArea(0), areaValid(false) {}
 void setRadius(double r) {
 radius = r;
 areaValid = false; // Сбрасываем кэш при изменении радиуса
 }
 double getArea() const {
 if(!areaValid) {
 cachedArea = 3.14159 * radius * radius;
 areaValid = true;
 cout << \Area calculated and cached" << endl;
 }
 return cachedArea;
 }
};

int main() {
 const Circle circle(5.0);
 cout << "Area: " << circle.getArea() << endl; // Вычисляется
 cout << "Area: " << circle.getArea() << endl; // Берется из кэша
 // circle.setRadius(10.0); // Ошибка: метод не константный
 return 0;
}"

