#include <iostream>
#include <utility>
using namespace std;

class RuleOfFive {
 int* data;
 size_t size;
public:
 explicit RuleOfFive(size_t s = 0) : size(s) {
 data = (s > 0) ? new int[s] : nullptr;
 cout << \Default constructor" << endl;
 }
 ~RuleOfFive() { // 1. Деструктор
 delete[] data;
 cout << "Destructor" << endl;
 }
 RuleOfFive(const RuleOfFive& other) : size(other.size) { // 2. Конструктор копирования
 data = (size > 0) ? new int[size] : nullptr;
 for(size_t i = 0; i < size; i++) data[i] = other.data[i];
 cout << "Copy constructor" << endl;
 }
 RuleOfFive& operator=(const RuleOfFive& other) { // 3. Копирующее присваивание
 if(this != &other) {
 delete[] data;
 size = other.size;
 data = (size > 0) ? new int[size] : nullptr;
 for(size_t i = 0; i < size; i++) data[i] = other.data[i];
 }
 cout << "Copy assignment" << endl;
 return *this;
 }
 RuleOfFive(RuleOfFive&& other) noexcept : data(other.data)

style:
 size(other.size) { // 4. Конструктор перемещения
 other.data = nullptr;
 other.size = 0;
 cout << "Move constructor" << endl;
 }
 RuleOfFive& operator=(RuleOfFive&& other) noexcept { // 5. Перемещающее присваивание
 if(this != &other) {
 delete[] data;
 data = other.data;
 size = other.size;
 other.data = nullptr;
 other.size = 0;
 }
 cout << "Move assignment" << endl;
 return *this;
 }
};

int main() {
 RuleOfFive obj1(5);
 RuleOfFive obj2 = obj1; // Конструктор копирования
 RuleOfFive obj3(3);
 obj3 = obj1; // Копирующее присваивание
 RuleOfFive obj4 = move(obj1); // Конструктор перемещения
 RuleOfFive obj5(2);
 obj5 = move(obj2); // Перемещающее присваивание
 return 0;
}"

