 other.size = 0;
 std::cout << "Move constructor" << std::endl;
 }
 RuleOfFive& operator=(RuleOfFive&& other) noexcept { // 5. Перемещающее присваивание
 if(this != &other) {
 delete[] data;
 data = other.data;
