code:
#include <iostream>
using namespace std;

class Base {
public:
 int publicVar;
protected:
 int protectedVar;
private:
 int privateVar;
};

class Derived : protected Base {
public:
 void accessBaseMembers() {
 publicVar = 1; // OK: publicVar становится protected в Derived
 protectedVar = 2; // OK: доступ к protected члену
 // privateVar = 3; // Ошибка: нет доступа к private члену Base
 }
};

class FurtherDerived : public Derived {
public:
 void accessFurther() {
 publicVar = 10; // OK: publicVar все еще protected
 protectedVar = 20; // OK: доступ к protected члену
 }
};

int main() {
 Derived d;
 // d.publicVar = 5; // Ошибка: publicVar теперь protected в Derived
 d.accessBaseMembers();
 return 0;
}

#include <iostream>

class Base {
public:
 int publicVar;
protected:
 int protectedVar;
private:
