#include <iostream>
using namespace std;

class MyArray {
 int* data;
 int size;
public:
 MyArray(int s) : size(s) {
 data = new int[size];
 }
 MyArray(const MyArray& other) : size(other.size) { // Конструктор копирования
 data = new int[size];
 for(int i = 0; i < size; i++) data[i] = other.data[i];
 }
 MyArray& operator=(const MyArray& other) { // Оператор присваивания
 if(this != &other) {
 delete[] data;
 size = other.size;
 data = new int[size];
 for(int i = 0; i < size; i++) data[i] = other.data[i];
 }
 return *this;
 }
 ~MyArray() { delete[] data; }
 void setValue(int index, int value) { data[index] = value; }
 int getValue(int index) const { return data[index]; }
};

int main() {
 MyArray a1(3);
 a1.setValue(0, 10); a1.setValue(1, 20); a1.setValue(2, 30);
 MyArray a2(1);
 a2 = a1; // Использование оператора присваивания
 cout << \a2[0] = " << a2.getValue(0) << endl;
 return 0;
}"

