#include <iostream>
using namespace std;

class Data {
public:
 int value;
 Data(int v = 0) : value(v) {}
 void print() const {
 cout << \Data: " << value << endl;
 }
 void multiply(int factor) {
 value *= factor;
 cout << "Multiplied: " << value << endl;
 }
};

class PointerToMember {
 Data* ptr;
public:
 PointerToMember(Data* p = nullptr) : ptr(p) {}
 Data* operator->() {
 return ptr;
 }
 template<typename T>
 T operator->*(T Data::*member) {
 return ptr->*member;
 }
};

int main() {
 Data data(42);
 PointerToMember pm(&data);
 // Доступ к полю через ->*
 int Data::*valPtr = &Data::value;
 cout << "Value via ->*: " << (pm->*valPtr) << endl;
 // Вызов метода через ->*
 void (Data::*printPtr)() const = &Data::print;
 (pm->*printPtr)();
 void (Data::*multPtr)(int) = &Data::multiply;
 (pm->*multPtr)(2);
 return 0;
}"

