#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class IntSet {
 vector<int> elements;
 void sortAndRemoveDuplicates() {
 sort(elements.begin(), elements.end());
 elements.erase(unique(elements.begin(), elements.end()), elements.end());
 }
public:
 IntSet() = default;
 IntSet(initializer_list<int> init) : elements(init) {
 sortAndRemoveDuplicates();
 }
 // Объединение множеств
 IntSet operator+(const IntSet& other) const {
 IntSet result = *this;
 result.elements.insert(result.elements.end(), other.elements.begin(), other.elements.end());
 result.sortAndRemoveDuplicates();
 return result;
 }
 // Пересечение множеств
 IntSet operator*(const IntSet& other) const {
 IntSet result;
 for(int elem : elements) {
 if(find(other.elements.begin(), other.elements.end(), elem) != other.elements.end()) {
 result.elements.push_back(elem);
 }
 }
 result.sortAndRemoveDuplicates();
 return result;
 }
 // Разность множеств
 IntSet operator-(const IntSet& other) const {
 IntSet result;
 for(int elem : elements) {
 if(find(other.elements.begin(), other.elements.end(), elem) == other.elements.end()) {
 result.elements.push_back(elem);
 }
 }
 return result;
 }
 // Принадлежность элемента
 bool operator()(int element) const {
 return find(elements.begin(), elements.end(), element) != elements.end();
 }
 // Подмножество
 bool operator<=(const IntSet& other) const {
 for(int elem : elements) {
 if(!other(elem)) return false;
 }
 return true;
 }
 // Добавление элемента
 IntSet& operator+=(int element) {
 if(!(*this)(element)) {
 elements.push_back(element);
 sortAndRemoveDuplicates();
 }
 return *this;
 }
 // Удаление элемента
 IntSet& operator-=(int element) {
 auto it = find(elements.begin(), elements.end(), element);
 if(it != elements.end()) {
 elements.erase(it);
 }
