#include <iostream>
#include <vector>
#include <string>
#include <sstream>
using namespace std;

int main() {
    string text = \C++ is a powerful programming language";
    vector<string> words;

    stringstream ss(text);
    string word;

    while (ss >> word) {
        words.push_back(word);
    }

    cout << "Слова в строке:" << endl;
    for (const auto& w : words) {
        cout << "\"" << w << "\" " << endl;
    }

    return 0;
}"

