    // Фильтрация четных чисел
    auto even_numbers = numbers | views::filter([](int n) { return n % 2 == 0; });
    cout << \Четные числа: ";
    for (int n : even_numbers) cout << n << " ";
    cout << endl;

    // Преобразование чисел в их квадраты
    auto squares = numbers | views::transform([](int n) { return n * n; });
    cout << "Квадраты: ";
    for (int n : squares) cout << n << " ";
    cout << endl;

    // Взять первые 5 элементов
    auto first_five = numbers | views::take(5);
    cout << "Первые 5: ";
    for (int n : first_five) cout << n << " ";
    cout << endl;

    // Пропустить первые 3 элемента
    auto skip_three = numbers | views::drop(3);
    cout << "После пропуска 3: ";
    for (int n : skip_three) cout << n << " ";
    cout << endl;

    // Обратный порядок
    auto reversed = numbers | views::reverse;
    cout << "В обратном порядке: ";
    for (int n : reversed) cout << n << " ";
    cout << endl;

