#include <iostream>
#include <vector>
#include <stdexcept>
using namespace std;

template<typename T>
class Stack {
private:
    vector<T> data;
public:
    void push(const T& value) {
        data.push_back(value);
    }

    void pop() {
        if (empty()) {
            throw runtime_error(\Стек пуст");
        }
        data.pop_back();
    }

    T& top() {
        if (empty()) {
            throw runtime_error("Стек пуст");
        }
        return data.back();
    }

    bool empty() const {
        return data.empty();
    }

    size_t size() const {
        return data.size();
    }
};

int main() {
    Stack<int> stack;
    stack.push(10);
    stack.push(20);
    stack.push(30);

    cout << "Верхний элемент: " << stack.top() << endl;
    stack.pop();
    cout << "После удаления: " << stack.top() << endl;
    return 0;
}"

