#include <iostream>
#include <type_traits>
using namespace std;

// Пользовательские type traits
template<typename T>
struct is_numeric : integral_constant<bool, 
 is_arithmetic<T>::value && !is_same<T, bool>::value && !is_same<T, char>::value> {};

template<typename T>
struct is_string : integral_constant<bool, 
 is_same<T, string>::value || is_same<T, const char*>::value> {};

// Класс, использующий type traits
template<typename T>
class Container {
 static_assert(!is_void<T>::value, \Cannot use void type");
 T value;
public:
 Container(const T& v) : value(v) {}
 void print() const {
 if constexpr (is_numeric<T>::value) {
 cout << "Numeric value: " << value << endl;
 } else if constexpr (is_string<T>::value) {
 cout << "String value: \"" << value << "\"" << endl;
 } else {
 cout << "Other type: " << value << endl;
 }
 }
};

int main() {
 Container<int> c1(42);
 Container<double> c2(3.14);
 Container<string> c3("Hello");
 Container<const char*> c4("World");
 // Container<void> c5; // Ошибка компиляции из-за static_assert
 c1.print();
 c2.print();
 c3.print();
 c4.print();
 return 0;
}"

