#include <iostream>
#include <type_traits>
using namespace std;

class Serializer {
public:
 // Основной шаблон
 template<typename T>
 string serialize(const T& value) const {
 if constexpr (is_arithmetic_v<T>) {
 return \Number: " + to_string(value);
 } else {
 return "Object: " + string(value);
 }
 }
};

// Специализация для bool
template<>
string Serializer::serialize<bool>(const bool& value) const {
 return "Boolean: " + string(value ? "true" : "false");
}

// Специализация для string
template<>
string Serializer::serialize<string>(const string& value) const {
 return "String: \"" + value + "\"";
}

int main() {
 Serializer serializer;
 cout << serializer.serialize(42) << endl;
 cout << serializer.serialize(3.14) << endl;
 cout << serializer.serialize(true) << endl;
 cout << serializer.serialize(false) << endl;
 cout << serializer.serialize(string("Hello")) << endl;
 cout << serializer.serialize("World") << endl; // Использует основной шаблон
 return 0;
}"

#include <iostream>
#include <type_traits>
#include <string>

class Serializer {
public:
 // Основной шаблон
 template<typename T>
 std::string serialize(const T& value) const {
 if constexpr (std::is_arithmetic_v<T>) {
 return \Number: " + std::to_string(value);
 } else {
 return "Object: " + std::string(value);
 }
 }
};

// Специализация для bool
template<>
std::string Serializer::serialize<bool>(const bool& value) const {
 return "Boolean: " + std::string(value ? "true" : "false");
}

// Специализация для string
template<>
std::string Serializer::serialize<std::string>(const std::string& value) const {
 return "String: \"" + value + "\"";
}

int main() {
 Serializer serializer;
 std::cout << serializer.serialize(42) << std::endl;
 std::cout << serializer.serialize(3.14) << std::endl;
 std::cout << serializer.serialize(true) << std::endl;
 std::cout << serializer.serialize(false) << std::endl;
 std::cout << serializer.serialize(std::string("Hello")) << std::endl;
 std::cout << serializer.serialize("World") << std::endl; // Использует основной шаблон
 return 0;
}"

