#include <concepts>
#include <vector>
#include <string>
using namespace std;

// Концепт для типов, поддерживающих арифметические операции
template<typename T>
concept Arithmetic = requires(T a, T b) {
    a + b;
    a - b;
    a * b;
    a / b;
};

// Концепт для типов с методом size()
template<typename T>
concept HasSize = requires(T container) {
    container.size();
};

// Функция, работающая только с арифметическими типами
template<Arithmetic T>
T multiply(T a, T b) {
    return a * b;
}

// Функция, работающая с контейнерами, имеющими метод size()
template<HasSize Container>
void printSize(const Container& container) {
    cout << \Размер: " << container.size() << endl;
}

// Концепт для вывода в поток
template<typename T>
concept Printable = requires(T value) {
    cout << value;
};

template<Printable T>
void print(const T& value) {
    cout << value << endl;
}

int main() {
    cout << "Умножение чисел: " << multiply(5

column6:
 3};
    printSize(vec);

    string str = "Hello";
    printSize(str);

    print("Печатаемая строка");
    print(42);

    return 0;
}"

