        std::cout << "Resource скопирован" << std::endl; 
    }

    Resource(Resource&& other) noexcept : data(std::move(other.data)) { 
        std::cout << "Resource перемещен" << std::endl; 
    }

    ~Resource() { 
        std::cout << "Resource уничтожен" << std::endl; 
    }
};

