    std::cout << "Обработка r-value ссылки" << std::endl;
}

void process(const Resource& r) {
    std::cout << "Обработка l-value ссылки" << std::endl;
}

int main() {
    std::cout << "=== L-value ссылки ===" << std::endl;
    Resource r1;
    process(r1);           // l-value

    std::cout << "\n=== R-value ссылки ===" << std::endl;
    process(Resource());   // r-value
    process(std::move(r1));     // r-value (явное преобразование)

    return 0;
}"

