public:
 Project(const string& n) : name(n) {
 cout << \Project created: " << name << endl;
 }
 ~Project() {
 cout << "Project destroyed: " << name << endl;
 }
 void work() const {
 cout << "Working on project: " << name << endl;
 }
};

class Team {
 vector<unique_ptr<Project>> projects;
 string teamName;
public:
 Team(const string& name) : teamName(name) {}
 // Конструктор перемещения
 Team(Team&& other) noexcept 
 : projects(move(other.projects))

style:
 teamName(move(other.teamName)) {
 cout << "Team move constructor: " << teamName << endl;
 }
 // Перемещающее присваивание
 Team& operator=(Team&& other) noexcept {
 if(this != &other) {
 projects = move(other.projects);
 teamName = move(other.teamName);
 }
 cout << "Team move assignment: " << teamName << endl;
 return *this;
 }
 // Запрещаем копирование
 Team(const Team&) = delete;
 Team& operator=(const Team&) = delete;
 void addProject(unique_ptr<Project> project) {
 projects.push_back(move(project));
 }
 void listProjects() const {
 cout << "Team " << teamName << " projects:" << endl;
 for(const auto& project : projects) {
 if(project) project->work();
 }
 }
};

int main() {
 Team alpha("Alpha");
 alpha.addProject(make_unique<Project>("Web Server"));
 alpha.addProject(make_unique<Project>("Database"));
 cout << "\n=== Moving team ===" << endl;
 Team beta = move(alpha); // Перемещаем всю команду
 beta.listProjects();
 // alpha.listProjects(); // Неопределенное поведение - alpha был перемещен
 return 0;
}"

