#include <iostream>
#include <thread>
#include <atomic>
#include <vector>
#include <chrono>
using namespace std;

class Counter {
private:
    atomic<int> value{0};
public:
    void increment() {
        value.fetch_add(1, memory_order_relaxed);
    }

    void decrement() {
        value.fetch_sub(1, memory_order_relaxed);
    }

    int get() const {
        return value.load(memory_order_relaxed);
    }
};

void worker(Counter& counter, int iterations) {
    for (int i = 0; i < iterations; i++) {
        counter.increment();
        this_thread::sleep_for(chrono::microseconds(1));
    }
}

int main() {
    Counter counter;
    vector<thread> threads;
    const int num_threads = 10;
    const int iterations_per_thread = 100;

    // Запускаем потоки
    for (int i = 0; i < num_threads; i++) {
        threads.emplace_back(worker, ref(counter), iterations_per_thread);
    }

    // Ждем завершения всех потоков
    for (auto& t : threads) {
        t.join();
    }

    cout << \Ожидаемое значение: " << num_threads * iterations_per_thread << endl;
    cout << "Фактическое значение: " << counter.get() << endl;

    // Демонстрация atomic_flag
    atomic_flag flag = ATOMIC_FLAG_INIT;

    auto flag_worker = [&flag](int id) {
        while (flag.test_and_set(memory_order_acquire)) {
            this_thread::yield();
        }
        cout << "Поток " << id << " вошел в критическую секцию" << endl;
        this_thread::sleep_for(chrono::milliseconds(100));
        flag.clear(memory_order_release);
    };

    thread t1(flag_worker

