// Заголовочный файл (интерфейс)
class MyClass {
private:
 class Impl; // Предварительное объявление реализации
 unique_ptr<Impl> pImpl; // Указатель на реализацию
public:
 MyClass(int value);
 ~MyClass(); // Должен быть объявлен здесь (из-за unique_ptr и неполного типа)
 void doSomething();
 int getValue() const;
};

// Файл реализации (.cpp)
class MyClass::Impl {
 int data;
 string name;
public:
 Impl(int val) : data(val), name(\PIMPL Example") {}
 void performOperation() {
 cout << name << " performing operation with data: " << data << endl;
 }
 int getData() const { return data; }
 void setData(int val) { data = val; }
};

MyClass::MyClass(int value) : pImpl(make_unique<Impl>(value)) {}
MyClass::~MyClass() = default; // Определен здесь

style:
 где Impl - полный тип
void MyClass::doSomething() { pImpl->performOperation(); }
int MyClass::getValue() const { return pImpl->getData(); }

int main() {
 MyClass obj(42);
 obj.doSomething();
 cout << "Value: " << obj.getValue() << endl;
 return 0;
}"

