code:
#include <iostream>
#include <vector>
#include <algorithm>
#include <memory>
using namespace std;

class Observer {
public:
    virtual void update(const string& message) = 0;
    virtual ~Observer() = default;
};

class Subject {
private:
    vector<Observer*> observers;
    string state;
public:
    void attach(Observer* observer) {
        observers.push_back(observer);
    }

    void detach(Observer* observer) {
        observers.erase(remove(observers.begin(), observers.end(), observer), observers.end());
    }

    void notify() {
        for (Observer* observer : observers) {
            observer->update(state);
        }
    }

    void setState(const string& newState) {
        state = newState;
        notify();
    }
};

class ConcreteObserver : public Observer {
private:
    string name;
public:
    ConcreteObserver(const string& name) : name(name) {}

    void update(const string& message) override {
        cout << name << \ получил сообщение: " << message << endl;
    }
};

int main() {
    Subject subject;

    ConcreteObserver observer1("Наблюдатель 1");
    ConcreteObserver observer2("Наблюдатель 2");

    subject.attach(&observer1);
    subject.attach(&observer2);

    subject.setState("Первое состояние");
    subject.setState("Второе состояние");

    subject.detach(&observer1);
    subject.setState("Третье состояние");

    return 0;
}"

#include <iostream>
#include <vector>
#include <algorithm>
#include <memory>

class Observer {
public:
    virtual void update(const std::string& message) = 0;
    virtual ~Observer() = default;
};

class Subject {
private:
    std::vector<Observer*> observers;
    std::string state;
public:
    void attach(Observer* observer) {
        observers.push_back(observer);
    }

    void detach(Observer* observer) {
        observers.erase(std::remove(observers.begin(), observers.end(), observer), observers.end());
    }

    void notify() {
        for (Observer* observer : observers) {
            observer->update(state);
        }
    }

    void setState(const std::string& newState) {
        state = newState;
        notify();
    }
};

class ConcreteObserver : public Observer {
private:
    std::string name;
public:
    ConcreteObserver(const std::string& name) : name(name) {}

    void update(const std::string& message) override {
        std::cout << name << \ получил сообщение: " << message << std::endl;
    }
};

int main() {
    Subject subject;

    ConcreteObserver observer1("Наблюдатель 1");
    ConcreteObserver observer2("Наблюдатель 2");

    subject.attach(&observer1);
    subject.attach(&observer2);

    subject.setState("Первое состояние");
    subject.setState("Второе состояние");

    subject.detach(&observer1);
    subject.setState("Третье состояние");

    return 0;
}"

#include <iostream>
#include <vector>
#include <memory>
#include <string>
#include <map>
#include <functional>
using namespace std;

// Базовый интерфейс для плагинов
class IPlugin {
public:
    virtual ~IPlugin() = default;
    virtual string getName() const = 0;
    virtual string getVersion() const = 0;
    virtual void execute() = 0;
};

// Менеджер плагинов
class PluginManager {
private:
    map<string, unique_ptr<IPlugin>> plugins;

public:
    void registerPlugin(unique_ptr<IPlugin> plugin) {
        string name = plugin->getName();
        plugins[name] = move(plugin);
        cout << \Зарегистрирован плагин: " << name << endl;
    }

    void unregisterPlugin(const string& name) {
        auto it = plugins.find(name);
        if (it != plugins.end()) {
            cout << "Удален плагин: " << name << endl;
            plugins.erase(it);
        }
    }

    void executePlugin(const string& name) {
        auto it = plugins.find(name);
        if (it != plugins.end()) {
            cout << "Выполнение плагина '" << name << "':" << endl;
            it->second->execute();
        } else {
            cout << "Плагин '" << name << "' не найден" << endl;
        }
    }

    void listPlugins() const {
        cout << "\nЗарегистрированные плагины:" << endl;
        for (const auto& [name

style:
 plugin] : plugins) {
            cout << "- " << name << " v" << plugin->getVersion() << endl;
        }
    }

    size_t getPluginCount() const {
        return plugins.size();
    }
};

// Конкретные реализации плагинов

class HelloPlugin : public IPlugin {
public:
    string getName() const override {
        return "HelloPlugin";
    }

    string getVersion() const override {
        return "1.0";
    }

    void execute() override {
        cout << "Hello from HelloPlugin!" << endl;
    }
};

class MathPlugin : public IPlugin {
public:
    string getName() const override {
        return "MathPlugin";
    }

    string getVersion() const override {
        return "1.1";
    }

    void execute() override {
        cout << "MathPlugin: 2 + 2 = " << (2 + 2) << endl;
        cout << "MathPlugin: sqrt(16) = " << sqrt(16) << endl;
    }
};

class TimePlugin : public IPlugin {
public:
    string getName() const override {
        return "TimePlugin";
    }

    string getVersion() const override {
        return "2.0";
    }

    void execute() override {
        // Простая имитация времени
        cout << "TimePlugin: Текущее время - 14:30:45" << endl;
    }
};

// Фабрика для создания плагинов
class PluginFactory {
public:
    static unique_ptr<IPlugin> createPlugin(const string& type) {
        if (type == "hello") {
            return make_unique<HelloPlugin>();
        } else if (type == "math") {
            return make_unique<MathPlugin>();
        } else if (type == "time") {
            return make_unique<TimePlugin>();
        }
        return nullptr;
    }

    static vector<string> getAvailableTypes() {
        return {"hello"

keywords:
 "time"};
    }
};

int main() {
    PluginManager manager;

    // Регистрируем плагины через фабрику
    cout << "Регистрация плагинов..." << endl;
    for (const auto& type : PluginFactory::getAvailableTypes()) {
        auto plugin = PluginFactory::createPlugin(type);
        if (plugin) {
            manager.registerPlugin(move(plugin));
        }
    }

    // Демонстрация работы
    cout << "\n=== Демонстрация системы плагинов ===" << endl;

    manager.listPlugins();

    cout << "\nТестирование плагинов:" << endl;
    manager.executePlugin("HelloPlugin");
    manager.executePlugin("MathPlugin");
    manager.executePlugin("TimePlugin");
    manager.executePlugin("NonExistentPlugin");

    // Динамическое управление
    cout << "\nДинамическое управление:" << endl;
    manager.unregisterPlugin("MathPlugin");
    manager.listPlugins();

    // Добавление нового плагина
    cout << "\nДобавление нового плагина:" << endl;
    auto newPlugin = make_unique<HelloPlugin>();
    manager.registerPlugin(move(newPlugin));

    cout << "\nИтоговое количество плагинов: " << manager.getPluginCount() << endl;

    return 0;
}"

