using namespace std;

class FileReader {
private:
    ifstream file;
    string filename;

public:
    explicit FileReader(const string& name) : filename(name) {
        file.open(filename);
        if (!file.is_open()) {
            throw runtime_error(\Не удалось открыть файл: " + filename);
        }
        cout << "Файл открыт: " << filename << endl;
    }

    ~FileReader() {
        if (file.is_open()) {
            file.close();
            cout << "Файл закрыт: " << filename << endl;
        }
    }

    vector<string> readAllLines() {
        vector<string> lines;
        string line;
        while (getline(file

style:
 line)) {
            lines.push_back(line);
        }
        return lines;
    }

    bool hasMoreLines() const {
        return !file.eof();
    }

    // Запрещаем копирование
    FileReader(const FileReader&) = delete;
    FileReader& operator=(const FileReader&) = delete;

    // Разрешаем перемещение
    FileReader(FileReader&&) = default;
    FileReader& operator=(FileReader&&) = default;
};

int main() {
    try {
        FileReader reader("output.txt");
        auto lines = reader.readAllLines();

        cout << "\nПрочитано строк: " << lines.size() << endl;
        for (size_t i = 0; i < lines.size(); ++i) {
            cout << "  " << i + 1 << ": " << lines[i] << endl;
        }

    } catch (const exception& e) {
        cout << "Ошибка: " << e.what() << endl;
    }

    return 0;
}"

