#include <iostream>
#include <coroutine>
#include <memory>
#include <vector>
using namespace std;

template<typename T>
struct Generator {
    struct promise_type {
        T current_value;

        Generator get_return_object() {
            return Generator{handle_type::from_promise(*this)};
        }

        suspend_always initial_suspend() { return {}; }
        suspend_always final_suspend() noexcept { return {}; }
        void unhandled_exception() { terminate(); }

        suspend_always yield_value(T value) {
            current_value = value;
            return {};
        }

        void return_void() {}
    };

    using handle_type = coroutine_handle<promise_type>;

    handle_type coro;

    Generator(handle_type h) : coro(h) {}
    ~Generator() { if (coro) coro.destroy(); }

    T value() const { return coro.promise().current_value; }

    bool move_next() {
        if (!coro.done()) {
            coro.resume();
            return !coro.done();
        }
        return false;
    }
};

Generator<int> fibonacci(int n) {
    int a = 0, b = 1;
    for (int i = 0; i < n; i++) {
        co_yield a;
        int next = a + b;
        a = b;
        b = next;
    }
}

int main() {
    auto fib_gen = fibonacci(10);

    cout << \Первые 10 чисел Фибоначчи:" << endl;
    while (fib_gen.move_next()) {
        cout << fib_gen.value() << " ";
    }
    cout << endl;

    return 0;
}"

