        std::vector<std::uint8_t> data(input.begin(), input.end());
        std::uint64_t bit_len = data.size() * 8;

        data.push_back(0x80);
        while ((data.size() * 8) % 512 != 448) {
            data.push_back(0x00);
        }

        for (int i = 0; i < 8; i++) {
            data.push_back((bit_len >> (56 - i * 8)) & 0xFF);
        }

        std::uint32_t h[8] = {
            0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a,
            0x510e527f, 0x9b05688c, 0x1f83d9ab, 0x5be0cd19
        };

        for (std::size_t chunk = 0; chunk < data.size(); chunk += 64) {
            std::uint32_t w[64];
            for (int i = 0; i < 16; i++) {
                w[i] = (data[chunk + i*4] << 24) | (data[chunk + i*4 + 1] << 16) | 
                       (data[chunk + i*4 + 2] << 8) | data[chunk + i*4 + 3];
            }

            for (int i = 16; i < 64; i++) {
                w[i] = gamma1(w[i-2]) + w[i-7] + gamma0(w[i-15]) + w[i-16];
            }

            std::uint32_t a = h[0], b = h[1], c = h[2], d = h[3];
            std::uint32_t e = h[4], f = h[5], g = h[6], h_val = h[7];

            for (int i = 0; i < 64; i++) {
                std::uint32_t t1 = h_val + sigma1(e) + ch(e, f, g) + k[i] + w[i];
                std::uint32_t t2 = sigma0(a) + maj(a, b, c);
                h_val = g;
                g = f;
                f = e;
                e = d + t1;
                d = c;
                c = b;
                b = a;
                a = t1 + t2;
            }

            h[0] += a; h[1] += b; h[2] += c; h[3] += d;
            h[4] += e; h[5] += f; h[6] += g; h[7] += h_val;
        }

        std::stringstream ss;
        for (int i = 0; i < 8; i++) {
            ss << std::hex << std::setw(8) << std::setfill('0') << h[i];
        }
        return ss.str();
    }
};

