#include <iostream>
#include <vector>
#include <string>
#include <map>
#include <bitset>
using namespace std;

class LZWCompressor {
private:
    map<string, int> dictionary;
    int dict_size;

public:
    LZWCompressor() {
        // Инициализация словаря с ASCII символами
        for (int i = 0; i < 256; i++) {
            dictionary[string(1, static_cast<char>(i))] = i;
        }
        dict_size = 256;
    }

    vector<int> compress(const string& input) {
        string w;
        vector<int> result;

        for (char c : input) {
            string wc = w + c;
            if (dictionary.find(wc) != dictionary.end()) {
                w = wc;
            } else {
                result.push_back(dictionary[w]);
                dictionary[wc] = dict_size++;
                w = string(1, c);
            }
        }

        if (!w.empty()) {
            result.push_back(dictionary[w]);
        }

        return result;
    }

    string decompress(const vector<int>& compressed) {
        map<int, string> dictionary;

        // Инициализация словаря с ASCII символами
        for (int i = 0; i < 256; i++) {
            dictionary[i] = string(1, static_cast<char>(i));
        }

        int dict_size = 256;
        string w(1, static_cast<char>(compressed[0]));
        string result = w;

        for (size_t i = 1; i < compressed.size(); i++) {
            int k = compressed[i];
            string entry;

            if (dictionary.find(k) != dictionary.end()) {
                entry = dictionary[k];
            } else if (k == dict_size) {
                entry = w + w[0];
            } else {
                throw runtime_error(\Ошибка декомпрессии: неверный код");
            }

            result += entry;
            dictionary[dict_size++] = w + entry[0];
            w = entry;
        }

        return result;
    }
};

int main() {
    LZWCompressor lzw;
    string input;

    cout << "Введите строку для сжатия: ";
    getline(cin

style:
 input);

    auto compressed = lzw.compress(input);

    cout << "Сжатые коды: ";
    for (int code : compressed) {
        cout << code << " ";
    }
    cout << endl;

    cout << "Коэффициент сжатия: " 
         << (static_cast<double>(input.length()) / compressed.size()) << endl;

    string decompressed = lzw.decompress(compressed);
    cout << "Расжатая строка: " << decompressed << endl;

    cout << "Совпадение: " << (input == decompressed ? "Да" : "Нет") << endl;

    return 0;
}"

