        dict_size = 256;
    }

    std::vector<int> compress(const std::string& input) {
        std::string w;
        std::vector<int> result;

        for (char c : input) {
            std::string wc = w + c;
            if (dictionary.find(wc) != dictionary.end()) {
                w = wc;
            } else {
                result.push_back(dictionary[w]);
                dictionary[wc] = dict_size++;
                w = std::string(1, c);
            }
        }

        if (!w.empty()) {
            result.push_back(dictionary[w]);
        }

        return result;
    }

    std::string decompress(const std::vector<int>& compressed) {
        std::map<int, std::string> dictionary;

        // Инициализация словаря с ASCII символами
        for (int i = 0; i < 256; i++) {
            dictionary[i] = std::string(1, static_cast<char>(i));
        }

        int dict_size = 256;
        std::string w(1, static_cast<char>(compressed[0]));
        std::string result = w;

        for (std::size_t i = 1; i < compressed.size(); i++) {
            int k = compressed[i];
            std::string entry;

            if (dictionary.find(k) != dictionary.end()) {
                entry = dictionary[k];
            } else if (k == dict_size) {
                entry = w + w[0];
            } else {
                throw std::runtime_error(\Ошибка декомпрессии: неверный код");
            }

            result += entry;
            dictionary[dict_size++] = w + entry[0];
            w = entry;
        }

        return result;
    }
};

int main() {
    LZWCompressor lzw;
    std::string input;

    std::cout << "Введите строку для сжатия: ";
    std::getline(std::cin

style:
 input);

    auto compressed = lzw.compress(input);

    std::cout << "Сжатые коды: ";
    for (int code : compressed) {
        std::cout << code << " ";
    }
    std::cout << std::endl;

    std::cout << "Коэффициент сжатия: " 
         << (static_cast<double>(input.length()) / compressed.size()) << std::endl;

    std::string decompressed = lzw.decompress(compressed);
    std::cout << "Расжатая строка: " << decompressed << std::endl;

    std::cout << "Совпадение: " << (input == decompressed ? "Да" : "Нет") << std::endl;

    return 0;
}"

