#include <iostream>
#include <vector>
#include <random>
#include <cmath>
#include <algorithm>
using namespace std;

class NeuralNetwork {
private:
    vector<vector<double>> weights_ih; // веса input->hidden
    vector<vector<double>> weights_ho; // веса hidden->output
    vector<double> bias_h;
    vector<double> bias_o;

    double learning_rate;

    double sigmoid(double x) {
        return 1.0 / (1.0 + exp(-x));
    }

    double sigmoid_derivative(double x) {
        return x * (1.0 - x);
    }

public:
    NeuralNetwork(int input_size, int hidden_size, int output_size, double lr = 0.1) 
        : learning_rate(lr) {

        random_device rd;
        mt19937 gen(rd());
        uniform_real_distribution<> dis(-1.0, 1.0);

        // Инициализация весов
        weights_ih.resize(hidden_size, vector<double>(input_size));
        weights_ho.resize(output_size, vector<double>(hidden_size));

        bias_h.resize(hidden_size);
        bias_o.resize(output_size);

        for (int i = 0; i < hidden_size; i++) {
            for (int j = 0; j < input_size; j++) {
                weights_ih[i][j] = dis(gen);
            }
            bias_h[i] = dis(gen);
        }

        for (int i = 0; i < output_size; i++) {
            for (int j = 0; j < hidden_size; j++) {
                weights_ho[i][j] = dis(gen);
            }
            bias_o[i] = dis(gen);
        }
    }

    vector<double> feedforward(const vector<double>& inputs) {
        vector<double> hidden(weights_ih.size());
        vector<double> output(weights_ho.size());

        // Вычисление скрытого слоя
        for (int i = 0; i < hidden.size(); i++) {
            hidden[i] = 0;
            for (int j = 0; j < inputs.size(); j++) {
                hidden[i] += inputs[j] * weights_ih[i][j];
            }
            hidden[i] += bias_h[i];
            hidden[i] = sigmoid(hidden[i]);
        }

        // Вычисление выходного слоя
        for (int i = 0; i < output.size(); i++) {
            output[i] = 0;
            for (int j = 0; j < hidden.size(); j++) {
                output[i] += hidden[j] * weights_ho[i][j];
            }
            output[i] += bias_o[i];
            output[i] = sigmoid(output[i]);
        }

        return output;
    }

    void train(const vector<double>& inputs, const vector<double>& targets) {
        // Прямое распространение
        auto hidden = vector<double>(weights_ih.size());
        auto outputs = vector<double>(weights_ho.size());

        // Вычисление скрытого слоя
        for (int i = 0; i < hidden.size(); i++) {
            hidden[i] = 0;
            for (int j = 0; j < inputs.size(); j++) {
                hidden[i] += inputs[j] * weights_ih[i][j];
            }
            hidden[i] += bias_h[i];
            hidden[i] = sigmoid(hidden[i]);
        }

        // Вычисление выходного слоя
        for (int i = 0; i < outputs.size(); i++) {
            outputs[i] = 0;
            for (int j = 0; j < hidden.size(); j++) {
                outputs[i] += hidden[j] * weights_ho[i][j];
            }
            outputs[i] += bias_o[i];
            outputs[i] = sigmoid(outputs[i]);
        }

        // Обратное распространение ошибки
        vector<double> output_errors(outputs.size());
        for (int i = 0; i < outputs.size(); i++) {
            output_errors[i] = targets[i] - outputs[i];
        }

        vector<double> hidden_errors(hidden.size());
        for (int i = 0; i < hidden.size(); i++) {
            hidden_errors[i] = 0;
            for (int j = 0; j < outputs.size(); j++) {
                hidden_errors[i] += output_errors[j] * weights_ho[j][i];
            }
        }

        // Обновление весов hidden->output
        for (int i = 0; i < outputs.size(); i++) {
            for (int j = 0; j < hidden.size(); j++) {
                weights_ho[i][j] += learning_rate * output_errors[i] * 
                                   sigmoid_derivative(outputs[i]) * hidden[j];
            }
            bias_o[i] += learning_rate * output_errors[i] * sigmoid_derivative(outputs[i]);
        }

        // Обновление весов input->hidden
        for (int i = 0; i < hidden.size(); i++) {
            for (int j = 0; j < inputs.size(); j++) {
                weights_ih[i][j] += learning_rate * hidden_errors[i] * 
                                   sigmoid_derivative(hidden[i]) * inputs[j];
            }
            bias_h[i] += learning_rate * hidden_errors[i] * sigmoid_derivative(hidden[i]);
        }
    }
};

int main() {
    // Нейросеть для задачи XOR
    NeuralNetwork nn(2, 4, 1, 0.5);

    vector<vector<double>> training_inputs = {
        {0, 0}, {0, 1}, {1, 0}, {1, 1}
    };

    vector<vector<double>> training_outputs = {
        {0}, {1}, {1}, {0}
    };

    // Обучение
    for (int epoch = 0; epoch < 10000; epoch++) {
        for (int i = 0; i < training_inputs.size(); i++) {
            nn.train(training_inputs[i], training_outputs[i]);
        }
    }

    // Тестирование
    cout << \Тестирование нейросети XOR:" << endl;
    for (const auto& input : training_inputs) {
        auto output = nn.feedforward(input);
        cout << input[0] << " XOR " << input[1] << " = " << output[0] << endl;
    }

    return 0;
}"

