#include <iostream>
#include <string>
#include <vector>
#include <memory>
#include <sstream>
#include <cctype>
using namespace std;

class Parser {
private:
    string input;
    size_t pos;

    char current_char() {
        return pos < input.length() ? input[pos] : '\0';
    }

    void advance() {
        pos++;
        while (pos < input.length() && isspace(input[pos])) {
            pos++;
        }
    }

    double parse_expression();
    double parse_term();
    double parse_factor();

public:
    Parser(const string& str) : input(str), pos(0) {
        // Пропускаем начальные пробелы
        while (pos < input.length() && isspace(input[pos])) {
            pos++;
        }
    }

    double parse() {
        return parse_expression();
    }
};

double Parser::parse_expression() {
    double result = parse_term();

    while (current_char() == '+' || current_char() == '-') {
        char op = current_char();
        advance();
        double term = parse_term();

        if (op == '+') {
            result += term;
        } else {
            result -= term;
        }
    }

    return result;
}

double Parser::parse_term() {
    double result = parse_factor();

    while (current_char() == '*' || current_char() == '/') {
        char op = current_char();
        advance();
        double factor = parse_factor();

        if (op == '*') {
            result *= factor;
        } else {
            if (factor == 0) {
                throw runtime_error(\Деление на ноль");
            }
            result /= factor;
        }
    }

    return result;
}

double Parser::parse_factor() {
    if (current_char() == '(') {
        advance(); // пропускаем '('
        double result = parse_expression();
        if (current_char() != ')') {
            throw runtime_error("Ожидается ')'");
        }
        advance(); // пропускаем ')'
        return result;
    }

    if (isdigit(current_char()) || current_char() == '.') {
        string number;
        while (isdigit(current_char()) || current_char() == '.') {
            number += current_char();
            advance();
        }
        return stod(number);
    }

    throw runtime_error("Неожиданный символ: " + string(1

style:
 current_char()));
}

