#include <iostream>
#include <vector>
#include <utility>
using namespace std;

class LargeObject {
public:
    LargeObject(size_t size) : data(new int[size]), size(size) {
        cout << \Конструктор " << size << endl;
    }

    LargeObject(LargeObject&& other) noexcept 
        : data(other.data)

style:
 size(other.size) {
        other.data = nullptr;
        other.size = 0;
        cout << "Move конструктор" << endl;
    }

    LargeObject& operator=(LargeObject&& other) noexcept {
        if (this != &other) {
            delete[] data;
            data = other.data;
            size = other.size;
            other.data = nullptr;
            other.size = 0;
            cout << "Move оператор присваивания" << endl;
        }
        return *this;
    }

    ~LargeObject() {
        delete[] data;
        cout << "Деструктор" << endl;
    }

private:
    int* data;
    size_t size;
};

int main() {
    LargeObject obj1(1000);
    LargeObject obj2 = move(obj1);

    vector<LargeObject> objects;
    objects.push_back(LargeObject(500));

    return 0;
}"

