#include <iostream>
#include <vector>
#include <memory>
#include <string>
using namespace std;

class Command {
public:
    virtual void execute() = 0;
    virtual void undo() = 0;
    virtual ~Command() = default;
};

class TextEditor {
private:
    string text;

public:
    void addText(const string& newText) {
        text += newText;
    }

    void deleteText(size_t length) {
        if (length <= text.length()) {
            text = text.substr(0, text.length() - length);
        }
    }

    string getText() const {
        return text;
    }
};

class AddTextCommand : public Command {
private:
    TextEditor& editor;
    string addedText;

public:
    AddTextCommand(TextEditor& ed, const string& text) 
        : editor(ed), addedText(text) {}

    void execute() override {
        editor.addText(addedText);
        cout << \Текст добавлен: " << editor.getText() << endl;
    }

    void undo() override {
        editor.deleteText(addedText.length());
        cout << "Отмена: " << editor.getText() << endl;
    }
};

class CommandManager {
private:
    vector<unique_ptr<Command>> history;
    size_t current = 0;

public:
    void executeCommand(unique_ptr<Command> cmd) {
        if (current < history.size()) {
            history.resize(current);
        }
        cmd->execute();
        history.push_back(move(cmd));
        current++;
    }

    void undo() {
        if (current > 0) {
            current--;
            history[current]->undo();
        }
    }

    void redo() {
        if (current < history.size()) {
            history[current]->execute();
            current++;
        }
    }
};

