#include <iostream>
#include <memory>
#include <functional>
using namespace std;

class AnyCallable {
private:
    struct Concept {
        virtual ~Concept() = default;
        virtual void call() = 0;
    };

    template<typename T>
    struct Model : Concept {
        T callable;
        Model(T&& c) : callable(forward<T>(c)) {}
        void call() override { callable(); }
    };

    unique_ptr<Concept> pimpl;

public:
    template<typename T>
    AnyCallable(T&& callable) 
        : pimpl(make_unique<Model<T>>(forward<T>(callable))) {}

    void operator()() {
        pimpl->call();
    }
};

int main() {
    int counter = 0;

    AnyCallable f1([]() { cout << \Лямбда без захвата" << endl; });
    AnyCallable f2([&counter]() { 
        counter++;
        cout << "Лямбда с захватом

style:
 counter = " << counter << endl; 
    });

    f1();
    f2();
    f2();

    return 0;
}"

