code:
#include <iostream>
#include <cmath>
using namespace std;

int main() {
    double S = 100; // цена акции
    double K = 105; // страйк
    double T = 1;   // время
    double r = 0.05; // ставка
    double sigma = 0.2; // волатильность

    double d1 = (log(S/K) + (r + sigma*sigma/2)*T) / (sigma*sqrt(T));
    double d2 = d1 - sigma*sqrt(T);

    // Упрощенный расчет для демонстрации
    double call_price = S * 0.6 - K * exp(-r*T) * 0.4;
    cout << \Примерная цена опциона: " << call_price << endl;
    return 0;
}"

