class Resource {
public:
    Resource() { cout << \Resource acquired" << endl; }
    ~Resource() { cout << "Resource destroyed" << endl; }
    void doSomething() { cout << "Resource used" << endl; }
};

int main() {
    // unique_ptr
    unique_ptr<Resource> ptr1 = make_unique<Resource>();
    ptr1->doSomething();

    // shared_ptr
    shared_ptr<Resource> ptr2 = make_shared<Resource>();
    shared_ptr<Resource> ptr3 = ptr2;
    cout << "Shared count: " << ptr2.use_count() << endl;

    // weak_ptr
    weak_ptr<Resource> weakPtr = ptr2;
    if (auto shared = weakPtr.lock()) {
        shared->doSomething();
    }

    return 0;
}"

#include <iostream>
