#include <iostream>
#include <vector>
#include <stack>
using namespace std;

struct TreeNode {
    int val;
    vector<TreeNode*> children;
    TreeNode(int x) : val(x) {}
};

void dfs(TreeNode* root) {
    if (!root) return;

    stack<TreeNode*> st;
    st.push(root);

    while (!st.empty()) {
        TreeNode* node = st.top();
        st.pop();

        cout << node->val << \ ";

        // Добавляем детей в обратном порядке для правильного обхода
        for (auto it = node->children.rbegin(); it != node->children.rend(); ++it) {
            st.push(*it);
        }
    }
}

int main() {
    TreeNode* root = new TreeNode(1);
    root->children.push_back(new TreeNode(2));
    root->children.push_back(new TreeNode(3));
    root->children[0]->children.push_back(new TreeNode(4));
    root->children[0]->children.push_back(new TreeNode(5));
    root->children[1]->children.push_back(new TreeNode(6));

    cout << "DFS обход: ";
    dfs(root);
    cout << endl;

    return 0;
}"

#include <iostream>
#include <unordered_map>
#include <list>
using namespace std;

class LRUCache {
private:
    int capacity;
    list<pair<int, int>> cache;
    unordered_map<int, list<pair<int, int>>::iterator> map;

public:
    LRUCache(int cap) : capacity(cap) {}

    int get(int key) {
        if (map.find(key) == map.end()) {
            return -1;
        }

        // Перемещаем в начало
        cache.splice(cache.begin(), cache, map[key]);
        return map[key]->second;
    }

    void put(int key, int value) {
        if (map.find(key) != map.end()) {
            // Обновляем значение и перемещаем в начало
            map[key]->second = value;
            cache.splice(cache.begin(), cache, map[key]);
            return;
        }

        if (cache.size() == capacity) {
            // Удаляем самый старый элемент
            int lastKey = cache.back().first;
            cache.pop_back();
            map.erase(lastKey);
        }

        // Добавляем новый элемент
        cache.emplace_front(key, value);
        map[key] = cache.begin();
    }
};

int main() {
