#include <iostream>
#include <vector>
#include <queue>
#include <climits>
using namespace std;

vector<int> dijkstra(const vector<vector<pair<int, int>>>& graph, int start) {
    int n = graph.size();
    vector<int> dist(n, INT_MAX);
    dist[start] = 0;

    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
    pq.push({0, start});

    while (!pq.empty()) {
        int currentDist = pq.top().first;
        int u = pq.top().second;
        pq.pop();

        if (currentDist > dist[u]) continue;

        for (const auto& edge : graph[u]) {
            int v = edge.first;
            int weight = edge.second;

            if (dist[u] + weight < dist[v]) {
                dist[v] = dist[u] + weight;
                pq.push({dist[v], v});
            }
        }
    }

    return dist;
}

int main() {
    int n = 5;
    vector<vector<pair<int, int>>> graph(n);

    graph[0].push_back({1, 4});
    graph[0].push_back({2, 1});
    graph[1].push_back({3, 1});
    graph[2].push_back({1, 2});
    graph[2].push_back({3, 5});
    graph[3].push_back({4, 3});

    vector<int> dist = dijkstra(graph, 0);

    cout << \Кратчайшие расстояния от вершины 0:" << endl;
    for (int i = 0; i < n; i++) {
        cout << "До вершины " << i << ": " << dist[i] << endl;
    }

    return 0;
}"

#include <iostream>
#include <coroutine>
#include <vector>
using namespace std;

struct Generator {
    struct promise_type {
        int current_value;

        Generator get_return_object() {
            return Generator{coroutine_handle<promise_type>::from_promise(*this)};
        }

        suspend_always initial_suspend() { return {}; }
        suspend_always final_suspend() noexcept { return {}; }
        void unhandled_exception() {}

        suspend_always yield_value(int value) {
            current_value = value;
            return {};
        }

        void return_void() {}
    };

    coroutine_handle<promise_type> coro;

    Generator(coroutine_handle<promise_type> h) : coro(h) {}
    ~Generator() { if (coro) coro.destroy(); }

    int next() {
        coro.resume();
        return coro.promise().current_value;
    }

    bool done() {
        return coro.done();
    }
};

Generator fibonacci(int n) {
    int a = 0, b = 1;
    for (int i = 0; i < n; i++) {
        co_yield a;
        int temp = a + b;
        a = b;
        b = temp;
    }
}

int main() {
    auto gen = fibonacci(10);

    cout << \Числа Фибоначчи: ";
    while (!gen.done()) {
        cout << gen.next() << " ";
    }
    cout << endl;

    return 0;
}"

