#include <iostream>
#include <cmath>
#include <random>
using namespace std;

class RSA {
private:
    long long p, q, n, phi, e, d;

    bool isPrime(long long num) {
        if (num < 2) return false;
        for (long long i = 2; i * i <= num; i++) {
            if (num % i == 0) return false;
        }
        return true;
    }

    long long gcd(long long a, long long b) {
        while (b) {
            long long temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }

    long long modPow(long long base, long long exponent, long long mod) {
        long long result = 1;
        base = base % mod;
        while (exponent > 0) {
            if (exponent & 1) {
                result = (result * base) % mod;
            }
            exponent = exponent >> 1;
            base = (base * base) % mod;
        }
        return result;
    }

    long long modInverse(long long a, long long m) {
        long long m0 = m, t, q;
        long long x0 = 0, x1 = 1;

        if (m == 1) return 0;

        while (a > 1) {
            q = a / m;
            t = m;
            m = a % m;
            a = t;
            t = x0;
            x0 = x1 - q * x0;
            x1 = t;
        }

        if (x1 < 0) x1 += m0;
        return x1;
    }

public:
    RSA() {
        // Простые числа для демонстрации
        p = 61;
        q = 53;
        n = p * q;
        phi = (p - 1) * (q - 1);

        // Выбор открытой экспоненты
        e = 17;
        while (gcd(e, phi) != 1) {
            e++;
        }

        // Вычисление закрытой экспоненты
        d = modInverse(e, phi);
    }

    long long encrypt(long long message) {
        return modPow(message, e, n);
    }

    long long decrypt(long long encrypted) {
        return modPow(encrypted, d, n);
    }

    void printKeys() {
        cout << \Открытый ключ (e

column6:
 " << n << ")" << endl;
    }
};

int main() {
    RSA rsa;
    rsa.printKeys();

    long long message = 42;
    cout << "Исходное сообщение: " << message << endl;

    long long encrypted = rsa.encrypt(message);
    cout << "Зашифрованное: " << encrypted << endl;

    long long decrypted = rsa.decrypt(encrypted);
    cout << "Расшифрованное: " << decrypted << endl;

    return 0;
}"

