#include <iostream>
#include <vector>
#include <algorithm>
#include <memory>
using namespace std;

class Observer {
public:
    virtual ~Observer() = default;
    virtual void update(const string& message) = 0;
};

class Subject {
private:
    vector<Observer*> observers;
    string state;

public:
    void attach(Observer* observer) {
        observers.push_back(observer);
    }

    void detach(Observer* observer) {
        observers.erase(remove(observers.begin(), observers.end(), observer), observers.end());
    }

    void setState(const string& newState) {
        state = newState;
        notify();
    }

    string getState() const {
        return state;
    }

    void notify() {
        for (Observer* observer : observers) {
            observer->update(state);
        }
    }
};

class ConcreteObserver : public Observer {
private:
    string name;

public:
    ConcreteObserver(const string& n) : name(n) {}

    void update(const string& message) override {
        cout << name << \ получил сообщение: " << message << endl;
    }
};

int main() {
    Subject subject;

    ConcreteObserver observer1("Наблюдатель 1");
    ConcreteObserver observer2("Наблюдатель 2");
    ConcreteObserver observer3("Наблюдатель 3");

    subject.attach(&observer1);
    subject.attach(&observer2);
    subject.attach(&observer3);

    subject.setState("Первое состояние");
    cout << endl;

    subject.detach(&observer2);
    subject.setState("Второе состояние");

    return 0;
}"

#include <iostream>
#include <vector>
#include <utility>
using namespace std;

class Resource {
private:
    vector<int> data;

public:
    Resource(size_t size) : data(size) {
        cout << \Конструктор: выделено " << size << " элементов" << endl;
    }

    // Конструктор перемещения
    Resource(Resource&& other) noexcept : data(move(other.data)) {
        cout << "Конструктор перемещения" << endl;
    }

    // Оператор перемещения
    Resource& operator=(Resource&& other) noexcept {
        cout << "Оператор перемещения" << endl;
        if (this != &other) {
            data = move(other.data);
        }
        return *this;
    }

    // Запрещаем копирование
    Resource(const Resource&) = delete;
    Resource& operator=(const Resource&) = delete;

    void print() const {
        cout << "Размер данных: " << data.size() << endl;
    }
};

Resource createResource() {
    return Resource(1000); // RVO/move semantics
}

int main() {
    cout << "Создание ресурса 1..." << endl;
    Resource res1(1000);

    cout << "\nСоздание ресурса 2 через перемещение..." << endl;
    Resource res2 = move(res1);

    cout << "\nРесурс 1 после перемещения:" << endl;
    res1.print();

    cout << "\nРесурс 2 после перемещения:" << endl;
    res2.print();

    cout << "\nСоздание ресурса через функцию..." << endl;
    Resource res3 = createResource();

    return 0;
}"

#include <iostream>
#include <vector>
using namespace std;

void merge(vector<int>& arr, int left, int mid, int right) {
    int n1 = mid - left + 1;
    int n2 = right - mid;

    vector<int> L(n1), R(n2);

    for (int i = 0; i < n1; i++)
        L[i] = arr[left + i];
    for (int j = 0; j < n2; j++)
        R[j] = arr[mid + 1 + j];

    int i = 0, j = 0, k = left;

    while (i < n1 && j < n2) {
        if (L[i] <= R[j]) {
            arr[k] = L[i];
            i++;
        } else {
            arr[k] = R[j];
            j++;
        }
        k++;
    }

    while (i < n1) {
        arr[k] = L[i];
        i++;
        k++;
    }

    while (j < n2) {
        arr[k] = R[j];
        j++;
        k++;
    }
}

void mergeSort(vector<int>& arr, int left, int right) {
    if (left >= right) return;

    int mid = left + (right - left) / 2;
    mergeSort(arr, left, mid);
    mergeSort(arr, mid + 1, right);
    merge(arr, left, mid, right);
}

