#include <iostream>
#include <chrono>
#include <thread>
#include <cmath>
using namespace std;
using namespace std::chrono;

void demonstrateChrono() {
    // Точки времени
    auto start = high_resolution_clock::now();

    // Имитация работы
    this_thread::sleep_for(milliseconds(100));

    auto end = high_resolution_clock::now();

    // Разница времени
    auto duration = duration_cast<microseconds>(end - start);
    cout << \Время выполнения: " << duration.count() << " микросекунд" << endl;

    // Текущее время
    auto now = system_clock::now();
    auto now_time_t = system_clock::to_time_t(now);
    cout << "Текущее время: " << ctime(&now_time_t);

    // Работа с duration
    seconds sec(60);
    minutes min = duration_cast<minutes>(sec);
    cout << "60 секунд = " << min.count() << " минут" << endl;

    // Hours
    hours hr(2);
    auto total_minutes = duration_cast<minutes>(hr);
    cout << "2 часа = " << total_minutes.count() << " минут" << endl;
}

class Timer {
private:
    time_point<high_resolution_clock> start_time;

public:
    Timer() : start_time(high_resolution_clock::now()) {}

    void reset() {
        start_time = high_resolution_clock::now();
    }

    double elapsed() const {
        auto end = high_resolution_clock::now();
        auto duration = duration_cast<microseconds>(end - start_time);
        return duration.count() / 1000000.0;
    }
};

int main() {
    demonstrateChrono();

    cout << "\nИзмерение времени вычислений:" << endl;

    Timer timer;

    // Выполняем тяжелые вычисления
    double sum = 0;
    for (int i = 0; i < 1000000; i++) {
        sum += sin(i) * cos(i);
    }

    double elapsed = timer.elapsed();
    cout << "Время вычислений: " << elapsed << " секунд" << endl;
    cout << "Результат: " << sum << endl;

    return 0;
}"

#include <iostream>
#include <string>
#include <vector>
using namespace std;

const int PRIME = 101;

long long calculateHash(const string& str, int start, int end) {
    long long hash = 0;
    for (int i = start; i <= end; i++) {
        hash = (hash * 256 + str[i]) % PRIME;
    }
    return hash;
}

long long recalculateHash(long long oldHash, char oldChar, char newChar, int patternLen) {
    long long newHash = (oldHash - oldChar * pow(256, patternLen - 1)) * 256 + newChar;
    return newHash % PRIME;
}

vector<int> rabinKarpSearch(const string& text, const string& pattern) {
    vector<int> positions;
    int n = text.length();
    int m = pattern.length();

    if (m == 0 || n < m) return positions;

    long long patternHash = calculateHash(pattern, 0, m - 1);
    long long textHash = calculateHash(text, 0, m - 1);

    for (int i = 0; i <= n - m; i++) {
        if (patternHash == textHash) {
            // Проверяем посимвольно на случай коллизии
            bool match = true;
            for (int j = 0; j < m; j++) {
                if (text[i + j] != pattern[j]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                positions.push_back(i);
            }
        }

        // Пересчитываем хэш для следующего окна
        if (i < n - m) {
            textHash = recalculateHash(textHash, text[i], text[i + m], m);
            if (textHash < 0) {
                textHash += PRIME;
            }
        }
    }

    return positions;
}

int main() {
    string text = \ABABCABABACABC";
    string pattern = "ABAB";

    vector<int> positions = rabinKarpSearch(text

style:
 pattern);

    if (positions.empty()) {
        cout << "Паттерн не найден" << endl;
    } else {
        cout << "Паттерн найден на позициях: ";
        for (int pos : positions) {
            cout << pos << " ";
        }
        cout << endl;
    }

    return 0;
}"

