#include <iostream>
#include <ctime>
using namespace std;

int main() {
    struct tm date1 = {0};
    struct tm date2 = {0};

    date1.tm_year = 124; // 2024
    date1.tm_mon = 0;    // Январь
    date1.tm_mday = 1;   // 1 число

    date2.tm_year = 124; // 2024
    date2.tm_mon = 0;    // Январь
    date2.tm_mday = 15;  // 15 число

    time_t time1 = mktime(&date1);
    time_t time2 = mktime(&date2);

    double diff = difftime(time2, time1) / (60 * 60 * 24);
    cout << \Разница в днях: " << diff << endl;
    return 0;
}"

