#include <iostream>
#include <string>
using namespace std;

bool isValidEmail(const string& email) {
    size_t at_pos = email.find('@');
    size_t dot_pos = email.find('.', at_pos);

    return (at_pos != string::npos && 
            dot_pos != string::npos && 
            dot_pos > at_pos + 1 && 
            email.length() > dot_pos + 1);
}

int main() {
    string email = 	est@example.com";
    cout << "Email валиден: " << boolalpha << isValidEmail(email) << endl;
    return 0;
}"

#include <iostream>
using namespace std;

int factorial(int n) {
    if (n <= 1) return 1;
    return n * factorial(n - 1);
