#include <iostream>
#include <cmath>
#include <vector>
using namespace std;

int main() {
    vector<double> returns = {0.1, 0.05, -0.02, 0.08, -0.01};
    double riskFreeRate = 0.02;
    double downsideDev = 0.0;

    for (double r : returns) {
        if (r < riskFreeRate) {
            downsideDev += pow(r - riskFreeRate, 2);
        }
    }
    downsideDev = sqrt(downsideDev / returns.size());

    double avgReturn = 0.0;
    for (double r : returns) avgReturn += r;
    avgReturn /= returns.size();

    double sortinoRatio = (avgReturn - riskFreeRate) / downsideDev;
    cout << \Коэффициент Сортино: " << sortinoRatio << endl;
    return 0;
}"

#include <iostream>
#include <vector>
#include <cmath>
using namespace std;

int main() {
    vector<double> cashFlows = {50, 50, 50, 1050}; // купоны и номинал
    double yield = 0.05; // доходность
    double price = 0.0;
    double duration = 0.0;

    for (int i = 0; i < cashFlows.size(); i++) {
        double pv = cashFlows[i] / pow(1 + yield, i + 1);
        price += pv;
        duration += (i + 1) * pv;
    }

    duration /= price;
    cout << \Дюрация: " << duration << " лет" << endl;
    return 0;
}"

#include <iostream>
#include <vector>
#include <cmath>
using namespace std;

int main() {
    vector<double> cashFlows = {50, 50, 50, 1050};
    double yield = 0.05;
    double price = 0.0;
    double convexity = 0.0;

    for (int i = 0; i < cashFlows.size(); i++) {
        double pv = cashFlows[i] / pow(1 + yield, i + 1);
        price += pv;
        convexity += (i + 1) * (i + 2) * pv;
    }

    convexity /= (price * pow(1 + yield, 2));
    cout << \Выпуклость: " << convexity << endl;
    return 0;
}"

