#include <iostream>
#include <vector>
#include <cmath>
using namespace std;

double calculateNPV(const vector<double>& cashFlows, double rate) {
    double npv = 0.0;
    for (int i = 0; i < cashFlows.size(); i++) {
        npv += cashFlows[i] / pow(1 + rate, i);
    }
    return npv;
}

int main() {
    vector<double> cashFlows = {-1000, 300, 400, 500};
    double irr = 0.1; // начальное предположение

    // Упрощенный метод подбора
    for (int i = 0; i < 100; i++) {
        double npv = calculateNPV(cashFlows, irr);
        if (abs(npv) < 0.01) break;
        irr += (npv > 0) ? 0.001 : -0.001;
    }

    cout << \IRR: " << irr * 100 << "%" << endl;
    return 0;
}"

