#include <iostream>
#include <vector>
#include <cmath>
using namespace std;

int main() {
    vector<double> cashFlows = {-1000, 300, 400, 500};
    double financeRate = 0.08; // ставка финансирования
    double reinvestRate = 0.1; // ставка реинвестирования

    double pvNegative = 0.0;
    double fvPositive = 0.0;

    for (int i = 0; i < cashFlows.size(); i++) {
        if (cashFlows[i] < 0) {
            pvNegative += cashFlows[i] / pow(1 + financeRate, i);
        } else {
            fvPositive += cashFlows[i] * pow(1 + reinvestRate, cashFlows.size() - i - 1);
        }
    }

    double mirr = pow(fvPositive / abs(pvNegative), 1.0 / cashFlows.size()) - 1;
    cout << \MIRR: " << mirr * 100 << "%" << endl;
    return 0;
}"

