#include <iostream>
#include <cmath>
using namespace std;

double f(double x) {
    return x * x; // y = x^2
}

int main() {
    double a = 0, b = 2;
    int n = 1000;
    double h = (b - a) / n;
    double volume = 0;

    for (int i = 0; i < n; i++) {
        double x = a + i * h;
        double radius = f(x);
        volume += M_PI * radius * radius * h;
    }

    cout << \Объем тела вращения: " << volume << endl;
    return 0;
}"

#include <iostream>
#include <cmath>
using namespace std;

double f(double x) {
    return x * x;
}

double df(double x) {
    return 2 * x;
}

int main() {
    double a = 0, b = 2;
    int n = 1000;
    double h = (b - a) / n;
    double surfaceArea = 0;

    for (int i = 0; i < n; i++) {
        double x = a + i * h;
        double y = f(x);
        double derivative = df(x);
        surfaceArea += 2 * M_PI * y * sqrt(1 + derivative * derivative) * h;
    }

    cout << \Площадь поверхности тела вращения: " << surfaceArea << endl;
    return 0;
}"

