#include <iostream>
#include <cmath>
using namespace std;

double sqrtNewton(double n, double precision = 1e-10) {
    if (n < 0) return -1; // Ошибка
    if (n == 0) return 0;

    double x = n;
    while (true) {
        double next = 0.5 * (x + n / x);
        if (abs(next - x) < precision) break;
        x = next;
    }
    return x;
}

int main() {
    double number = 25.0;
    cout << \sqrt(" << number << ") = " << sqrtNewton(number) << endl;
    cout << "Проверка: " << sqrt(number) << endl;
    return 0;
}"

