 double calculateProjectCost(int projectId) const {
 auto project = findProjectById(projectId);
 if(!project) return 0.0;

 double totalSalaryCost = 0;
 for(int empId : project->teamMembers) {
 auto employee = findEmployeeById(empId);
 if(employee) {
 // Простой расчет: предполагаем 1 месяц работы
 totalSalaryCost += employee->salary;
 }
 }

 return totalSalaryCost;
 }

 void displayProjectBudgetReport(int projectId) const {
 auto project = findProjectById(projectId);
 if(project) {
 double salaryCost = calculateProjectCost(projectId);
 double remainingBudget = project->budget - salaryCost;

 cout << "
=== BUDGET REPORT FOR PROJECT " << project->name << " ===" << endl;
 cout << "Total Budget: $" << project->budget << endl;
 cout << "Salary Costs: $" << salaryCost << endl;
 cout << "Remaining Budget: $" << remainingBudget << endl;

 if(remainingBudget < 0) {
 cout << "WARNING: Project is over budget!" << endl;
 }
 } else {
 cout << "Project not found!" << endl;
 }
 }

