class Cache {
 map<string, pair<string, time_t>> data;
public:
 void set(string key, string value, int ttl = 60) {
 data[key] = {value, time(nullptr) + ttl};
 }
 string get(string key) {
 auto it = data.find(key);
 if(it != data.end() && it->second.second > time(nullptr)) {
 return it->second.first;
 }
 return ";
 }
};

class CircularBuffer {
 vector<int> buffer;
 int head, tail, size;
public:
 CircularBuffer(int capacity) : buffer(capacity), head(0), tail(0), size(0) {}
 void push(int value) {
 buffer[tail] = value;
 tail = (tail + 1) % buffer.size();
 if(size < buffer.size()) size++;
 else head = (head + 1) % buffer.size();
 }
 int pop() {
 if(size == 0) return -1;
 int value = buffer[head];
 head = (head + 1) % buffer.size();
 size--;
 return value;
 }
};

class ConnectionPool {
 queue<Connection> pool;
 int maxSize;
public:
 ConnectionPool(int max) : maxSize(max) {}
 Connection getConnection() {
 if(pool.empty()) return new Connection();
 Connection* conn = pool.front();
 pool.pop();
 return conn;
 }
 void returnConnection(Connection* conn) {
 if(pool.size() < maxSize) pool.push(conn);
 else delete conn;
 }
};

class RateLimiter {
 int maxRequests;
 time_t window;
 queue<time_t> requests;
public:
 RateLimiter(int max, time_t win) : maxRequests(max), window(win) {}
 bool allow() {
 time_t now = time(nullptr);
 while(!requests.empty() && requests.front() <= now - window) {
 requests.pop();
 }
 if(requests.size() < maxRequests) {
 requests.push(now);
 return true;
 }
 return false;
 }
};

