 }
 bool hasPath(int start, int end) {
 queue<int> q;
 set<int> visited;
 q.push(start);
 visited.insert(start);

 while(!q.empty()) {
 int current = q.front();
 q.pop();
 if(current == end) return true;
 for(int neighbor : adjacencyList[current]) {
 if(visited.find(neighbor) == visited.end()) {
 visited.insert(neighbor);
 q.push(neighbor);
 }
 }
 }
 return false;
 }
};

