 bool contains(int value) { return contains(root, value); }
};

class PriorityQueue {
 vector<pair<int, string>> heap;
 void heapifyUp(int index) {
 while(index > 0) {
 int parent = (index - 1) / 2;
 if(heap[parent].first >= heap[index].first) break;
 swap(heap[parent], heap[index]);
 index = parent;
 }
 }
 void heapifyDown(int index) {
 while(2 * index + 1 < heap.size()) {
 int left = 2 * index + 1;
 int right = 2 * index + 2;
 int largest = index;
 if(left < heap.size() && heap[left].first > heap[largest].first) largest = left;
 if(right < heap.size() && heap[right].first > heap[largest].first) largest = right;
 if(largest == index) break;
 swap(heap[index], heap[largest]);
 index = largest;
 }
 }
public:
 void push(int priority, string value) {
 heap.push_back({priority, value});
 heapifyUp(heap.size() - 1);
 }
 string pop() {
 string value = heap[0].second;
 heap[0] = heap.back();
 heap.pop_back();
 heapifyDown(0);
 return value;
 }
 bool empty() { return heap.empty(); }
};

class LRUCache {
 int capacity;
 list<pair<int, int>> items;
 unordered_map<int, list<pair<int, int>>::iterator> keyToItem;
public:
 LRUCache(int cap) : capacity(cap) {}
 int get(int key) {
 if(keyToItem.find(key) == keyToItem.end()) return -1;
 items.splice(items.begin(), items, keyToItem[key]);
 return keyToItem[key]->second;
 }
 void put(int key, int value) {
 if(keyToItem.find(key) != keyToItem.end()) {
 items.erase(keyToItem[key]);
 }
 items.push_front({key, value});
 keyToItem[key] = items.begin();
 if(keyToItem.size() > capacity) {
 int keyToRemove = items.back().first;
 keyToItem.erase(keyToRemove);
 items.pop_back();
 }
 }
};

