class ColorSpace {
 double r, g, b;
public:
 ColorSpace(double red, double green, double blue) : r(red), g(green), b(blue) {}
 vector<double> toHSV() {
 double maxVal = max({r, g, b});
 double minVal = min({r, g, b});
 double h, s, v = maxVal;

 double delta = maxVal - minVal;
 s = maxVal == 0 ? 0 : delta / maxVal;

 if(delta == 0) h = 0;
 else if(maxVal == r) h = (g - b) / delta + (g < b ? 6 : 0);
 else if(maxVal == g) h = (b - r) / delta + 2;
 else h = (r - g) / delta + 4;
 h /= 6;

 return {h, s, v};
 }
 vector<double> toHSL() {
 double maxVal = max({r, g, b});
 double minVal = min({r, g, b});
 double h, s, l = (maxVal + minVal) / 2;

 double delta = maxVal - minVal;
 s = delta == 0 ? 0 : delta / (1 - abs(2 * l - 1));

 if(delta == 0) h = 0;
 else if(maxVal == r) h = (g - b) / delta + (g < b ? 6 : 0);
 else if(maxVal == g) h = (b - r) / delta + 2;
 else h = (r - g) / delta + 4;
 h /= 6;

 return {h, s, l};
 }
};

