 void generateTable() {
 for(int i = 0; i < 256; i++) {
 uint32_t crc = i;
 for(int j = 0; j < 8; j++) {
 crc = (crc >> 1) ^ (crc & 1 ? 0xEDB88320 : 0);
 }
 table[i] = crc;
 }
 }
public:
