 uint32_t calculate(string data) {
 uint32_t crc = 0xFFFFFFFF;
 for(char c : data) {
 crc = table[(crc ^ c) & 0xFF] ^ (crc >> 8);
 }
 return crc ^ 0xFFFFFFFF;
 }
};

