 vector<double>(layers[i+1])));
 }
 }
 vector<double> forward(vector<double> input) {
 vector<double> current = input;
 for(auto& layer_weights : weights) {
 vector<double> next(layer_weights[0].size(), 0);
 for(int i = 0; i < current.size(); i++) {
 for(int j = 0; j < next.size(); j++) {
 next[j] += current[i] * layer_weights[i][j];
 }
 }
 current = next;
 }
 return current;
 }
};

