class Dijkstra {
 map<string, vector<pair<string, double>>> graph;
public:
 void addEdge(string u, string v, double weight) {
 graph[u].push_back({v, weight});
 graph[v].push_back({u, weight});
 }
 map<string, double> shortestPaths(string start) {
 map<string, double> distances;
 for(auto& [node, _] : graph) distances[node] = numeric_limits<double>::infinity();
 distances[start] = 0;

 set<pair<double, string>> pq;
 pq.insert({0, start});

 while(!pq.empty()) {
 string u = pq.begin()->second;
 pq.erase(pq.begin());

 for(auto& [v, weight] : graph[u]) {
 double alt = distances[u] + weight;
 if(alt < distances[v]) {
 pq.erase({distances[v], v});
 distances[v] = alt;
 pq.insert({alt, v});
 }
 }
 }
 return distances;
 }
};

class DFS {
 map<string, vector<string>> graph;
public:
 void addEdge(string u, string v) {
 graph[u].push_back(v);
 }
 vector<string> traverse(string start) {
 vector<string> result;
 set<string> visited;
 function<void(string)> dfs = [&](string node) {
 visited.insert(node);
 result.push_back(node);
 for(string neighbor : graph[node]) {
 if(visited.find(neighbor) == visited.end()) {
 dfs(neighbor);
 }
 }
 };
 dfs(start);
 return result;
 }
};

class BFS {
 map<string, vector<string>> graph;
public:
 void addEdge(string u, string v) {
 graph[u].push_back(v);
 }
 vector<string> traverse(string start) {
 vector<string> result;
 queue<string> q;
 set<string> visited;
 q.push(start);
 visited.insert(start);
 while(!q.empty()) {
 string current = q.front();
 q.pop();
 result.push_back(current);
 for(string neighbor : graph[current]) {
 if(visited.find(neighbor) == visited.end()) {
 visited.insert(neighbor);
 q.push(neighbor);
 }
 }
 }
 return result;
 }
};

class MergeSort {
public:
 vector<int> sort(vector<int> arr) {
 if(arr.size() <= 1) return arr;
 int mid = arr.size() / 2;
 vector<int> left(arr.begin(), arr.begin() + mid);
 vector<int> right(arr.begin() + mid, arr.end());
 left = sort(left);
 right = sort(right);
 return merge(left, right);
 }
 vector<int> merge(vector<int> left, vector<int> right) {
 vector<int> result;
 int i = 0, j = 0;
 while(i < left.size() && j < right.size()) {
 if(left[i] <= right[j]) result.push_back(left[i++]);
 else result.push_back(right[j++]);
 }
 while(i < left.size()) result.push_back(left[i++]);
 while(j < right.size()) result.push_back(right[j++]);
 return result;
 }
};

class QuickSort {
public:
 vector<int> sort(vector<int> arr) {
 if(arr.size() <= 1) return arr;
 int pivot = arr[arr.size() / 2];
 vector<int> left, middle, right;
 for(int x : arr) {
 if(x < pivot) left.push_back(x);
 else if(x == pivot) middle.push_back(x);
 else right.push_back(x);
 }
 left = sort(left);
 right = sort(right);
 left.insert(left.end(), middle.begin(), middle.end());
 left.insert(left.end(), right.begin(), right.end());
 return left;
 }
};

class BinarySearch {
public:
 int search(vector<int> arr, int target) {
 int left = 0, right = arr.size() - 1;
 while(left <= right) {
 int mid = left + (right - left) / 2;
 if(arr[mid] == target) return mid;
 if(arr[mid] < target) left = mid + 1;
 else right = mid - 1;
 }
 return -1;
 }
};

class HashTable {
 vector<list<pair<string, string>>> table;
 int size;
 int hash(string key) {
 int hash = 0;
 for(char c : key) hash = (hash * 31 + c) % size;
 return hash;
 }
public:
 HashTable(int s) : size(s), table(s) {}
 void put(string key, string value) {
 int index = hash(key);
 for(auto& [k, v] : table[index]) {
 if(k == key) {
 v = value;
 return;
 }
 }
 table[index].push_back({key, value});
 }
 string get(string key) {
 int index = hash(key);
 for(auto& [k, v] : table[index]) {
 if(k == key) return v;
 }
 return ";
 }
};

class BinarySearchTree {
 struct Node {
 int value;
 Node* left, right;
 Node(int val) : value(val), left(nullptr), right(nullptr) {}
 };
 Node root;
 Node* insert(Node* node, int value) {
 if(!node) return new Node(value);
 if(value < node->value) node->left = insert(node->left, value);
 else node->right = insert(node->right, value);
 return node;
 }
 bool contains(Node* node, int value) {
 if(!node) return false;
 if(value == node->value) return true;
 if(value < node->value) return contains(node->left, value);
 return contains(node->right, value);
 }
public:
 BinarySearchTree() : root(nullptr) {}
 void insert(int value) { root = insert(root, value); }
