};

class AVLTree {
 struct Node {
 int value, height;
 Node left, right;
 Node(int val) : value(val), height(1), left(nullptr), right(nullptr) {}
 };
 Node root;
 int height(Node node) { return node ? node->height : 0; }
 int balanceFactor(Node* node) { return node ? height(node->left) - height(node->right) : 0; }
 Node* rotateRight(Node* y) {
 Node* x = y->left;
 Node* T2 = x->right;
 x->right = y;
 y->left = T2;
 y->height = max(height(y->left), height(y->right)) + 1;
 x->height = max(height(x->left), height(x->right)) + 1;
 return x;
 }
 Node* insert(Node* node, int value) {
 if(!node) return new Node(value);
 if(value < node->value) node->left = insert(node->left, value);
 else node->right = insert(node->right, value);

 node->height = 1 + max(height(node->left), height(node->right));
 int balance = balanceFactor(node);

 if(balance > 1 && value < node->left->value) return rotateRight(node);
 // other rotations omitted for brevity
 return node;
 }
public:
 AVLTree() : root(nullptr) {}
 void insert(int value) { root = insert(root, value); }
};

