class Heap {
 vector<int> data;
 void heapifyUp(int index) {
 while(index > 0) {
 int parent = (index - 1) / 2;
 if(data[parent] >= data[index]) break;
 swap(data[parent], data[index]);
 index = parent;
 }
 }
 void heapifyDown(int index) {
 while(2 * index + 1 < data.size()) {
 int left = 2 * index + 1;
 int right = 2 * index + 2;
 int largest = index;
 if(left < data.size() && data[left] > data[largest]) largest = left;
 if(right < data.size() && data[right] > data[largest]) largest = right;
 if(largest == index) break;
 swap(data[index], data[largest]);
 index = largest;
 }
 }
public:
 void push(int value) {
 data.push_back(value);
 heapifyUp(data.size() - 1);
 }
 int pop() {
 int value = data[0];
 data[0] = data.back();
 data.pop_back();
 heapifyDown(0);
 return value;
 }
 bool empty() { return data.empty(); }
};

class PriorityQueue {
 vector<pair<int, string>> heap;
 void heapifyUp(int index) {
 while(index > 0) {
 int parent = (index - 1) / 2;
 if(heap[parent].first >= heap[index].first) break;
 swap(heap[parent], heap[index]);
 index = parent;
 }
 }
 void heapifyDown(int index) {
 while(2 * index + 1 < heap.size()) {
 int left = 2 * index + 1;
 int right = 2 * index + 2;
 int largest = index;
 if(left < heap.size() && heap[left].first > heap[largest].first) largest = left;
 if(right < heap.size() && heap[right].first > heap[largest].first) largest = right;
 if(largest == index) break;
 swap(heap[index], heap[largest]);
 index = largest;
 }
 }
public:
 void push(int priority, string value) {
 heap.push_back({priority, value});
 heapifyUp(heap.size() - 1);
 }
 string pop() {
 string value = heap[0].second;
 heap[0] = heap.back();
 heap.pop_back();
 heapifyDown(0);
 return value;
 }
 bool empty() { return heap.empty(); }
};

