class KMP {
 vector<int> buildLPS(string pattern) {
 vector<int> lps(pattern.length(), 0);
 int len = 0, i = 1;
 while(i < pattern.length()) {
 if(pattern[i] == pattern[len]) {
 lps[i++] = ++len;
 } else {
 if(len != 0) len = lps[len - 1];
 else lps[i++] = 0;
 }
 }
 return lps;
 }
public:
 vector<int> search(string text, string pattern) {
 vector<int> lps = buildLPS(pattern);
 vector<int> result;
 int i = 0, j = 0;
 while(i < text.length()) {
 if(pattern[j] == text[i]) {
 i++; j++;
 }
 if(j == pattern.length()) {
 result.push_back(i - j);
 j = lps[j - 1];
 } else if(i < text.length() && pattern[j] != text[i]) {
 if(j != 0) j = lps[j - 1];
 else i++;
 }
 }
 return result;
 }
};

class BoyerMoore {
 map<char, int> buildBadCharTable(string pattern) {
 map<char, int> table;
 for(int i = 0; i < pattern.length(); i++) {
 table[pattern[i]] = i;
 }
 return table;
 }
public:
 vector<int> search(string text, string pattern) {
 map<char, int> badChar = buildBadCharTable(pattern);
 vector<int> result;
 int s = 0;
 while(s <= text.length() - pattern.length()) {
 int j = pattern.length() - 1;
 while(j >= 0 && pattern[j] == text[s + j]) j--;
 if(j < 0) {
 result.push_back(s);
 s += (s + pattern.length() < text.length()) ? 
 pattern.length() - badChar[text[s + pattern.length()]] : 1;
 } else {
 s += max(1, j - badChar[text[s + j]]);
 }
 }
 return result;
 }
};

class RabinKarp {
 const int prime = 101;
 long calculateHash(string str, int len) {
 long hash = 0;
 for(int i = 0; i < len; i++) {
 hash += str[i] * pow(prime, i);
 }
 return hash;
 }
 long recalculateHash(string str, int oldIndex, int newIndex, long oldHash, int patternLen) {
 long newHash = oldHash - str[oldIndex];
 newHash /= prime;
 newHash += str[newIndex] * pow(prime, patternLen - 1);
 return newHash;
 }
public:
 vector<int> search(string text, string pattern) {
 vector<int> result;
 int n = text.length(), m = pattern.length();
 long patternHash = calculateHash(pattern, m);
 long textHash = calculateHash(text, m);

 for(int i = 0; i <= n - m; i++) {
 if(patternHash == textHash && text.substr(i, m) == pattern) {
 result.push_back(i);
 }
 if(i < n - m) {
 textHash = recalculateHash(text, i, i + m, textHash, m);
 }
 }
 return result;
 }
};

class RSA {
 long long p, q, n, phi, e, d;
 long long modPow(long long base, long long exponent, long long mod) {
 long long result = 1;
 while(exponent > 0) {
 if(exponent % 2 == 1) result = (result * base) % mod;
 base = (base * base) % mod;
 exponent /= 2;
 }
 return result;
 }
public:
 RSA() {
 p = 61, q = 53; // small primes for demo
 n = p * q;
 phi = (p - 1) * (q - 1);
 e = 17;
 d = 2753; // modular inverse of e mod phi
 }
 long long encrypt(long long message) {
 return modPow(message, e, n);
 }
 long long decrypt(long long ciphertext) {
 return modPow(ciphertext, d, n);
 }
};

