 for(char c : str) {
 hash ^= c;
 hash *= 1099511628211ULL;
 }
 return hash;
 }
 size_t jenkins(string str) {
 size_t hash = 0;
 for(char c : str) {
 hash += c;
 hash += (hash << 10);
 hash ^= (hash >> 6);
 }
 hash += (hash << 3);
 hash ^= (hash >> 11);
 hash += (hash << 15);
 return hash;
 }
};

class CRC32 {
 uint32_t table[256];
 void generateTable() {
 for(int i = 0; i < 256; i++) {
 uint32_t crc = i;
 for(int j = 0; j < 8; j++) {
 crc = (crc >> 1) ^ (crc & 1 ? 0xEDB88320 : 0);
 }
 table[i] = crc;
 }
 }
public:
 CRC32() { generateTable(); }
 uint32_t calculate(string data) {
 uint32_t crc = 0xFFFFFFFF;
 for(char c : data) {
 crc = table[(crc ^ c) & 0xFF] ^ (crc >> 8);
 }
 return crc ^ 0xFFFFFFFF;
 }
};

