class LRUCache {
 int capacity;
 list<pair<int, int>> items;
 unordered_map<int, list<pair<int, int>>::iterator> keyToItem;
public:
 LRUCache(int cap) : capacity(cap) {}
 int get(int key) {
 if(keyToItem.find(key) == keyToItem.end()) return -1;
 items.splice(items.begin(), items, keyToItem[key]);
 return keyToItem[key]->second;
 }
 void put(int key, int value) {
 if(keyToItem.find(key) != keyToItem.end()) {
 items.erase(keyToItem[key]);
 }
 items.push_front({key, value});
 keyToItem[key] = items.begin();
 if(keyToItem.size() > capacity) {
 int keyToRemove = items.back().first;
 keyToItem.erase(keyToRemove);
 items.pop_back();
 }
 }
};

