 if(index >= size) throw std::out_of_range(Index out of range");
 return data[index];
 }
 const int& operator[](size_t index) const {
 if(index >= size) throw std::out_of_range("Index out of range");
 return data[index];
 }
 size_t getSize() const { return size; }
};"

