template<typename T>
class ObjectPool {
 std::queue<std::unique_ptr<T>> available;
 std::vector<std::unique_ptr<T>> inUse;
public:
 std::unique_ptr<T> acquire() {
 if(available.empty()) {
 available.push(std::make_unique<T>());
 }
 auto obj = std::move(available.front());
 available.pop();
 inUse.push_back(std::move(obj));
 return std::move(inUse.back());
 }
 void release(std::unique_ptr<T> obj) {
 available.push(std::move(obj));
 }
};

