template<typename L, typename R>
class AddExpr {
 const L& lhs;
 const R& rhs;
public:
 AddExpr(const L& l, const R& r) : lhs(l), rhs(r) {}
 auto operator[](size_t i) const { return lhs[i] + rhs[i]; }
 size_t size() const { return lhs.size(); }
};

template<typename T>
class Vector {
 std::vector<T> data;
public:
 Vector(size_t size) : data(size) {}
 T& operator[](size_t i) { return data[i]; }
 const T& operator[](size_t i) const { return data[i]; }
 size_t size() const { return data.size(); }
 template<typename E>
 Vector& operator=(const E& expr) {
 for(size_t i = 0; i < data.size(); i++) {
 data[i] = expr[i];
 }
 return *this;
 }
};

template<typename L, typename R>
AddExpr<L, R> operator+(const L& lhs, const R& rhs) {
 return AddExpr<L, R>(lhs, rhs);
}

struct input_iterator_tag {};
struct forward_iterator_tag : input_iterator_tag {};
struct bidirectional_iterator_tag : forward_iterator_tag {};
struct random_access_iterator_tag : bidirectional_iterator_tag {};

template<typename Iterator>
void advance_impl(Iterator& it, int n, input_iterator_tag) {
 while(n-- > 0) ++it;
}

template<typename Iterator>
void advance_impl(Iterator& it, int n, random_access_iterator_tag) {
 it += n;
}

template<typename Iterator>
void advance(Iterator& it, int n) {
 advance_impl(it, n, typename Iterator::iterator_category());
}

class String {
 char* data;
 size_t length;
 void swap(String& other) noexcept {
 std::swap(data, other.data);
 std::swap(length, other.length);
 }
public:
 String(const char* str = ") {
 length = strlen(str);
 data = new char[length + 1];
 strcpy(data, str);
 }
 String(const String& other) : String(other.data) {}
 String(String&& other) noexcept : data(other.data), length(other.length) {
 other.data = nullptr;
 other.length = 0;
 }
 String& operator=(String other) {
 swap(other);
 return *this;
 }
 ~String() { delete[] data; }
};

struct Empty {};

template<typename T, typename Allocator = Empty>
class Container : private Allocator {
 T* data;
 size_t size;
public:
 Container(size_t n) : size(n) {
 data = static_cast<T*>(this->allocate(size * sizeof(T)));
 }
 ~Container() {
 this->deallocate(data, size * sizeof(T));
 }
};

class ThreadSafeSingleton {
 static std::atomic<ThreadSafeSingleton> instance;
 static std::mutex mutex;
 ThreadSafeSingleton() = default;
public:
 static ThreadSafeSingleton& getInstance() {
 ThreadSafeSingleton tmp = instance.load(std::memory_order_acquire);
 std::atomic_thread_fence(std::memory_order_acquire);
 if(tmp == nullptr) {
 std::lock_guardstd::mutex lock(mutex);
 tmp = instance.load(std::memory_order_relaxed);
 if(tmp == nullptr) {
 tmp = new ThreadSafeSingleton();
 std::atomic_thread_fence(std::memory_order_release);
 instance.store(tmp, std::memory_order_relaxed);
 }
 }
 return *tmp;
 }
};

