class SharedPtr {
 T* ptr;
 int* count;
public:
 SharedPtr(T* p = nullptr) : ptr(p), count(new int(1)) {}
 SharedPtr(const SharedPtr& other) : ptr(other.ptr), count(other.count) {
 ++(count);
 }
 SharedPtr& operator=(const SharedPtr& other) {
 if(this != &other) {
 if(--(count) == 0) {
 delete ptr;
 delete count;
 }
 ptr = other.ptr;
 count = other.count;
 ++(*count);
 }
 return this;
 }
 ~SharedPtr() {
 if(--(count) == 0) {
 delete ptr;
 delete count;
 }
 }
 T& operator*() { return ptr; }
 T operator->() { return ptr; }
};

class TTLCache {
 struct Node {
 string key, value;
 time_t expiry;
 Node* prev, next;
 };
 unordered_map<string, Node> cache;
 Node* head, tail;
 int capacity;

 void moveToHead(Node node) {
 removeNode(node);
 addToHead(node);
 }

 void removeNode(Node* node) {
 node->prev->next = node->next;
 node->next->prev = node->prev;
 }

 void addToHead(Node* node) {
 node->next = head->next;
 node->prev = head;
 head->next->prev = node;
 head->next = node;
 }

 void evictLRU() {
 Node* node = tail->prev;
 removeNode(node);
 cache.erase(node->key);
 delete node;
 }

public:
 TTLCache(int cap) : capacity(cap) {
 head = new Node();
 tail = new Node();
 head->next = tail;
 tail->prev = head;
 }

 void put(const string& key, const string& value, int ttl) {
 if(cache.find(key) != cache.end()) {
 cache[key]->value = value;
 cache[key]->expiry = time(nullptr) + ttl;
 moveToHead(cache[key]);
 } else {
 if(cache.size() >= capacity) evictLRU();
 Node* node = new Node{key, value, time(nullptr) + ttl};
 cache[key] = node;
 addToHead(node);
 }
 }

 string get(const string& key) {
 if(cache.find(key) == cache.end()) return ";
 Node* node = cache[key];
 if(time(nullptr) > node->expiry) {
 removeNode(node);
 cache.erase(key);
 delete node;
 return ";
 }
 moveToHead(node);
 return node->value;
 }
};

class ThreadPool {
 vector<thread> workers;
 vector<queue<function<void()>>> tasks;
 vector<mutex> queueMutexes;
 vector<condition_variable> conditions;
 atomic<bool> stop;

 void workerThread(int threadId) {
 while(true) {
 function<void()> task;
 {
 unique_lock<mutex> lock(queueMutexes[threadId]);
 conditions[threadId].wait(lock, [this, threadId] {
 return stop || !tasks[threadId].empty();
 });
 if(stop && tasks[threadId].empty()) return;
 task = move(tasks[threadId].front());
 tasks[threadId].pop();
 }
 task();

 // Work stealing
 for(int i = 0; i < tasks.size(); ++i) {
 int target = (threadId + i) % tasks.size();
 if(target == threadId) continue;

 unique_lock<mutex> lock(queueMutexes[target], try_to_lock);
 if(lock && !tasks[target].empty()) {
 task = move(tasks[target].front());
 tasks[target].pop();
 lock.unlock();
 task();
 }
 }
 }
 }

public:
 ThreadPool(size_t numThreads) : stop(false) {
 tasks.resize(numThreads);
 queueMutexes.resize(numThreads);
 conditions.resize(numThreads);

 for(size_t i = 0; i < numThreads; ++i) {
 workers.emplace_back(&ThreadPool::workerThread, this, i);
 }
 }

 template<typename F>
 void enqueue(F&& task, int preferredThread = -1) {
 int threadId = (preferredThread == -1) ? rand() % tasks.size() : preferredThread;
 {
 unique_lock<mutex> lock(queueMutexes[threadId]);
 tasks[threadId].emplace(forward<F>(task));
 }
 conditions[threadId].notify_one();
 }

 ~ThreadPool() {
 stop = true;
 for(auto& cv : conditions) cv.notify_all();
 for(thread& worker : workers) worker.join();
 }
};

template<typename T>
class LockFreeQueue {
 struct Node {
 shared_ptr<T> data;
 atomic<Node> next;
 Node() : next(nullptr) {}
 };

 atomic<Node> head;
 atomic<Node> tail;

public:
 LockFreeQueue() {
 Node dummy = new Node();
 head.store(dummy);
 tail.store(dummy);
 }

 void push(T new_value) {
 shared_ptr<T> new_data = make_shared<T>(move(new_value));
 Node* new_node = new Node();
 new_node->data = new_data;

 while(true) {
 Node* current_tail = tail.load();
 Node* tail_next = current_tail->next.load();

 if(current_tail == tail.load()) {
 if(tail_next == nullptr) {
 if(current_tail->next.compare_exchange_weak(tail_next, new_node)) {
 tail.compare_exchange_weak(current_tail, new_node);
 return;
 }
 } else {
 tail.compare_exchange_weak(current_tail, tail_next);
 }
 }
 }
 }

 shared_ptr<T> pop() {
 while(true) {
 Node* current_head = head.load();
 Node* current_tail = tail.load();
 Node* head_next = current_head->next.load();

 if(current_head == head.load()) {
 if(current_head == current_tail) {
 if(head_next == nullptr) return shared_ptr<T>();
 tail.compare_exchange_weak(current_tail, head_next);
 } else {
 shared_ptr<T> res = head_next->data;
 if(head.compare_exchange_weak(current_head, head_next)) {
 delete current_head;
 return res;
 }
 }
 }
 }
 }
};

template<typename K, typename V>
class AVLTree {
 struct Node {
 K key;
 V value;
 int height;
 Node* left, right;
 Node(K k, V v) : key(k), value(v), height(1), left(nullptr), right(nullptr) {}
 };

 Node root;

 int height(Node* node) {
 return node ? node->height : 0;
 }

 int balanceFactor(Node* node) {
 return node ? height(node->left) - height(node->right) : 0;
 }

 void updateHeight(Node* node) {
 if(node) node->height = 1 + max(height(node->left), height(node->right));
 }

 Node* rotateRight(Node* y) {
 Node* x = y->left;
 Node* T2 = x->right;

 x->right = y;
 y->left = T2;

 updateHeight(y);
 updateHeight(x);

 return x;
 }

 Node* rotateLeft(Node* x) {
 Node* y = x->right;
 Node* T2 = y->left;

 y->left = x;
 x->right = T2;

 updateHeight(x);
 updateHeight(y);

 return y;
 }

 Node* balance(Node* node) {
 updateHeight(node);
 int bf = balanceFactor(node);

 if(bf > 1) {
 if(balanceFactor(node->left) < 0) node->left = rotateLeft(node->left);
 return rotateRight(node);
 }
 if(bf < -1) {
 if(balanceFactor(node->right) > 0) node->right = rotateRight(node->right);
 return rotateLeft(node);
 }
 return node;
 }

 Node* insert(Node* node, K key, V value) {
 if(!node) return new Node(key, value);

 if(key < node->key) node->left = insert(node->left, key, value);
 else if(key > node->key) node->right = insert(node->right, key, value);
 else node->value = value;

 return balance(node);
 }

public:
 AVLTree() : root(nullptr) {}

 void insert(K key, V value) {
 root = insert(root, key, value);
 }

 bool contains(K key) {
 Node* current = root;
 while(current) {
 if(key == current->key) return true;
 else if(key < current->key) current = current->left;
 else current = current->right;
 }
 return false;
 }
};

class EventSystem {
 struct Event {
 string type;
 function<void()> handler;
 int priority;
 time_t timestamp;

 bool operator<(const Event& other) const {
 if(priority != other.priority) return priority < other.priority;
 return timestamp > other.timestamp;
 }
 };

 priority_queue<Event> events;
 unordered_map<string, vector<function<void()>>> listeners;
 mutex mtx;

public:
 void subscribe(const string& eventType, function<void()> handler, int priority = 0) {
 lock_guard<mutex> lock(mtx);
 listeners[eventType].push_back(handler);
 }

 void emit(const string& eventType, int priority = 0) {
 lock_guard<mutex> lock(mtx);
 if(listeners.find(eventType) != listeners.end()) {
 for(auto& handler : listeners[eventType]) {
 events.push({eventType, handler, priority, time(nullptr)});
 }
 }
 }

 void processEvents(int maxEvents = 10) {
 lock_guard<mutex> lock(mtx);
 int processed = 0;
 while(!events.empty() && processed < maxEvents) {
 Event event = events.top();
 events.pop();
 event.handler();
 processed++;
 }
 }

 size_t pendingEvents() const {
 lock_guard<mutex> lock(mtx);
 return events.size();
 }
};

