class QueryCache {
 struct CacheEntry {
 string result;
 time_t timestamp;
 time_t expiry;
 vector<string> dependencies;
 };

 unordered_map<string, CacheEntry> cache;
 unordered_map<string, unordered_set<string>> dependencyIndex;
 mutex mtx;

 void invalidateDependencies(const vector<string>& deps) {
 for(const auto& dep : deps) {
 if(dependencyIndex.find(dep) != dependencyIndex.end()) {
 for(const auto& key : dependencyIndex[dep]) {
 cache.erase(key);
 }
 dependencyIndex[dep].clear();
 }
 }
 }

public:
 void put(const string& key, const string& result, int ttl, const vector<string>& deps = {}) {
 lock_guard<mutex> lock(mtx);

 // Инвалидация зависимостей
 invalidateDependencies(deps);

 // Добавление в кэш
 cache[key] = {result, time(nullptr), time(nullptr) + ttl, deps};

 // Обновление индекса зависимостей
 for(const auto& dep : deps) {
 dependencyIndex[dep].insert(key);
 }
 }

 string get(const string& key) {
 lock_guard<mutex> lock(mtx);

 if(cache.find(key) == cache.end()) return ";

 CacheEntry& entry = cache[key];

 // Проверка срока годности
 if(time(nullptr) > entry.expiry) {
 cache.erase(key);
 return ";
 }

 return entry.result;
 }

 void invalidate(const string& key) {
 lock_guard<mutex> lock(mtx);

 if(cache.find(key) != cache.end()) {
 // Удаление из индекса зависимостей
 for(const auto& dep : cache[key].dependencies) {
 dependencyIndex[dep].erase(key);
 }
 cache.erase(key);
 }
 }

 void invalidateByDependency(const string& dependency) {
 lock_guard<mutex> lock(mtx);
 invalidateDependencies({dependency});
 }

 size_t size() const {
 lock_guard<mutex> lock(mtx);
 return cache.size();
 }
};

